const dotenv = require("dotenv");
dotenv.config({ path: "../.env" });

const mongoose  = require("mongoose");
const Chapter   = require("../models/Chapter");
const Resource  = require("../models/Resource");

// ─────────────────────────────────────────────────────────
// HELPER — inserts PYQs + MCQs for one chapter
// Call this with the chapter DB object + your data arrays
// ─────────────────────────────────────────────────────────
const seedChapter = async (chapter, { pyqs, easyMCQ, mediumMCQ, hardMCQ }) => {
  const resources = [];

  pyqs.forEach((q, i) => {
    resources.push({
      chapterId:  chapter._id,
      type:       "pyq",
      title:      q.title || `PYQ Q${i + 1}`,
      question:   q.question,
      answer:     q.answer,
      year:       q.year,
      marks:      q.marks,
      difficulty: q.difficulty,
      order:      i + 1,
    });
  });

  easyMCQ.forEach((q, i) => {
    resources.push({
      chapterId:       chapter._id,
      type:            "mcq",
      testLevel:       "easy",
      title:           `Easy Q${i + 1}`,
      mcqQuestion:     q.q,
      mcqOptions:      q.opts,
      mcqCorrectIndex: q.ans,
      mcqExplanation:  q.exp,
      order:           i + 1,
    });
  });

  mediumMCQ.forEach((q, i) => {
    resources.push({
      chapterId:       chapter._id,
      type:            "mcq",
      testLevel:       "medium",
      title:           `Medium Q${i + 1}`,
      mcqQuestion:     q.q,
      mcqOptions:      q.opts,
      mcqCorrectIndex: q.ans,
      mcqExplanation:  q.exp,
      order:           i + 1,
    });
  });

  hardMCQ.forEach((q, i) => {
    resources.push({
      chapterId:       chapter._id,
      type:            "mcq",
      testLevel:       "hard",
      title:           `Hard Q${i + 1}`,
      mcqQuestion:     q.q,
      mcqOptions:      q.opts,
      mcqCorrectIndex: q.ans,
      mcqExplanation:  q.exp,
      order:           i + 1,
    });
  });

  await Resource.insertMany(resources);
  console.log(`  ✅ ${chapter.title} — ${resources.length} resources inserted`);
};


// ═════════════════════════════════════════════════════════
// CH 1 — THE RISE OF NATIONALISM IN EUROPE
// ═════════════════════════════════════════════════════════

const ch1_pyqs = [
  { title:"PYQ 2023", question:"What is meant by 'absolutist' as used by historians? How did absolutist regimes work in Europe?", answer:"Absolutist refers to a system of government where the monarch holds absolute, unquestionable power — not limited by constitutions, laws, or elected bodies. In 18th-century Europe, absolute monarchs controlled armies, judiciary, and finances. They suppressed dissent, jailed opponents without trial, and made laws by decree. Examples: Louis XVI in France, the Tsars of Russia. These regimes were characterised by centralised power, divine right of kings, and suppression of individual freedoms.", year:2023, marks:3, difficulty:"medium" },
  { title:"PYQ 2023", question:"Explain the role of culture — particularly Romanticism — in the development of nationalism in Europe.", answer:"Romanticism was a cultural movement that reacted against the rationalism of the Enlightenment. Romantic artists, poets and philosophers argued that nationalism should be built not on reason alone but on shared cultural heritage, emotions, history and traditions. Key contributions: (1) German philosopher Johann Gottfried Herder promoted the idea of 'volksgeist' (spirit of the people) expressed through folk songs, poetry and dances. (2) Romantic poets like Wordsworth and Goethe glorified nature and the vernacular language, helping people feel connected to their land. (3) Language became a tool of nationalism — standardising grammar books and dictionaries created a sense of shared identity. (4) Folk culture was collected and celebrated, making ordinary people feel part of a larger national community.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What steps did Napoleonic rule take that helped spread revolutionary ideas across Europe?", answer:"Napoleon's conquests spread French revolutionary ideas across Europe in several ways: (1) Napoleonic Code — abolished feudal privileges, established equality before the law, secured right to property, abolished serfdom. (2) Uniform system of weights and measures. (3) Abolition of internal customs duties — promoted free trade within conquered territories. (4) Improved roads and communication systems. (5) Standardised currencies. However, Napoleon also raised taxes, censored the press, and forced military service — creating resistance. His invasions paradoxically helped nationalism spread by making conquered peoples want to resist foreign domination, inspiring nationalist movements in Germany, Spain and Italy.", year:2022, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"Who was Frederic Sorrieu? Describe his vision of the world as shown in his 1848 painting.", answer:"Frederic Sorrieu was a French artist. In 1848 he created a series of utopian paintings depicting a world divided into democratic and social republics. In his painting, people of Europe and America are shown marching in a long procession, paying homage to the statue of Liberty. The people march in order nation by nation — identified by their national flags and costumes. The figures of Christ, angels and saints look down from the heavens approvingly. On the ground lie the shattered remains of absolutist symbols. His vision was of a world where all nations would live as free peoples in a fraternal federation.", year:2022, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"How did the Treaty of Vienna (1815) try to undo the changes brought by Napoleon? What was the conservative vision behind it?", answer:"The Congress of Vienna (1815) was organised by the conservative powers — Britain, Russia, Prussia and Austria — to restore the pre-Napoleonic order. Key measures: (1) The Bourbon dynasty was restored in France under Louis XVIII. (2) A series of states were set up on the boundaries of France to prevent future French expansion. (3) Prussia was given important new territories on its western frontier; Austria got control of northern Italy. (4) Poland was restored under Russian control. The conservative vision believed in preserving the traditional order — monarchy, church, and social hierarchy. They opposed liberalism and nationalism, fearing these ideas would destabilise their empires. Metternich declared that nationalism was a disease that threatened the empire.", year:2021, marks:5, difficulty:"hard" },
  { title:"PYQ 2021", question:"What do you understand by the term 'Zollverein'? What was its significance?", answer:"Zollverein was a customs union established in 1834 on the initiative of Prussia. It abolished tariff barriers between German states and created a unified economic zone. Significance: (1) It created a single currency and common set of weights and measures. (2) It boosted trade and economic activity across German states. (3) It demonstrated that German states could cooperate economically. (4) It helped generate a sense of German economic and ultimately national unity before political unification. It was one of the key preconditions for German political unification under Bismarck in 1871.", year:2021, marks:3, difficulty:"medium" },
  { title:"PYQ 2020", question:"Describe the events of the 1848 revolution in France and its impact on other European countries.", answer:"In February 1848, liberal nationalists in France revolted, overthrowing the monarchy of King Louis Philippe and establishing a republic. Impact: (1) The revolution inspired uprisings across Europe — in the German states, Italian states, Hungary, Poland and Bohemia. (2) In German states, Frankfurt Parliament was convened where elected representatives debated a constitution for a unified Germany. (3) In Hungary, nationalists under Kossuth demanded autonomy from Austria. (4) In Italy, revolts broke out in many states. (5) Workers in Paris demanded more radical social reforms. However, most of these revolutions were eventually suppressed by conservative forces, earning 1848 the description of 'the springtime of nations' — a brief flowering of nationalist and liberal ideals.", year:2020, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"What is a 'nation-state'? How did modern nationalism lead to the concept of the nation-state?", answer:"A nation-state is a political entity (state) that is aligned with a nation — a group of people sharing common culture, language, history and territory. Modern nationalism emerged in the late 18th century with the French Revolution, which introduced the idea that sovereignty belongs to the people (the nation), not the king. This led to the idea that political boundaries should match ethnic/cultural boundaries. People sharing a common identity began demanding their own independent state. This drove the unification of Germany and Italy and the dissolution of multi-ethnic empires like the Austro-Hungarian Empire.", year:2020, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"How did German unification happen? What role did Otto von Bismarck play?", answer:"German unification was achieved through a policy of 'blood and iron' under Otto von Bismarck, Chief Minister of Prussia. Process: (1) Bismarck fought three decisive wars — against Denmark (1864), Austria (1866), and France (1870-71). (2) After defeating France in 1871, the Prussian king Wilhelm I was proclaimed German Emperor in the Hall of Mirrors at Versailles. (3) Bismarck used Prussian military power, diplomatic skill, and economic strength (Zollverein) to unite the 39 German states. Unlike the liberal nationalists of 1848 who wanted unification through popular uprising, Bismarck achieved it through conservative state power.", year:2019, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"What is the significance of the allegory of 'Germania' in German nationalism?", answer:"Germania was the female allegorical figure representing the German nation. Key features of her imagery: (1) She wore a crown of oak leaves — the German oak symbolising heroism and strength. (2) She carried a sword — representing military power. (3) She wore a black, red and gold tricolour — the revolutionary flag of German nationalism. (4) She was often depicted with broken chains, representing freedom from oppression. Germania served to visualise and give a human, inspiring face to the abstract concept of German nationhood. She appeared in paintings, coins and statues, helping people feel emotionally connected to the idea of Germany as a nation.", year:2019, marks:3, difficulty:"medium" },
  { title:"PYQ 2023", question:"How did the French Revolution contribute to the development of nationalism in Europe?", answer:"The French Revolution (1789) was the first clear expression of modern nationalism. Contributions: (1) It introduced the idea that sovereignty belongs to the people — the 'nation' not the king. (2) New symbols were created — the tricolour flag, the Marseillaise anthem, the oaths of loyalty to the nation. (3) The Declaration of the Rights of Man established individual freedoms — press, speech, assembly. (4) The concept of 'La Patrie' (the fatherland) and 'le citoyen' (the citizen) gave people a sense of collective national identity. (5) The revolution abolished estates (class divisions) and created a single unified community of French citizens. These ideas then spread across Europe through Napoleon's conquests.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What was the significance of the 1848 liberal initiative in the German states? Why did it fail?", answer:"The Frankfurt Parliament of 1848 was a significant liberal initiative where elected representatives from the German states gathered to draft a constitution for a unified German nation. Significance: (1) First democratic experiment in German history. (2) Debated inclusion of all German-speaking peoples. (3) Offered the crown to the Prussian King. Failure: (1) Prussian King Frederick William IV rejected the crown, refusing to accept authority from a popular assembly. (2) Social divisions — middle class liberals were afraid of working class radicalism and distanced themselves from social demands. (3) Military suppressed uprisings. (4) Women were not given voting rights and sat only in the galleries. The failure showed that liberal nationalism alone could not achieve unification without military and state power.", year:2022, marks:5, difficulty:"hard" },
  { title:"PYQ 2021", question:"Explain the role of Giuseppe Mazzini in the Italian nationalist movement.", answer:"Giuseppe Mazzini was the most important ideologue of Italian nationalism. His contributions: (1) Founded 'Young Italy' — a secret society to spread nationalist ideas. (2) Founded 'Young Europe' — believing that God intended nations to be free peoples. (3) His vision was of a republican, democratic Italy unified through popular uprising. (4) He inspired two other famous leaders — Cavour and Garibaldi — who ultimately achieved unification. (5) His writings and propaganda spread revolutionary nationalist ideas. Metternich of Austria described him as 'the most dangerous enemy of our social order'. Though his direct attempts at revolution failed, his ideas laid the ideological foundation for Italian unification.", year:2021, marks:3, difficulty:"medium" },
  { title:"PYQ 2020", question:"Distinguish between the goals of liberal nationalism and conservative nationalism in 19th century Europe.", answer:"Liberal Nationalism: (1) Supported individual freedoms — press, speech, assembly. (2) Wanted constitutions limiting monarchs' power. (3) Believed in elected representative governments. (4) Supported free market economies. (5) Believed nationalism should emerge from popular will. (6) Examples: The Frankfurt Parliament, Young Italy. Conservative Nationalism: (1) Supported traditional order — monarchy, church, aristocracy. (2) Accepted nationalism only if it served existing power structures. (3) Used nationalism as a tool to strengthen state power. (4) Suppressed liberal and revolutionary movements. (5) Examples: Bismarck's 'blood and iron' unification of Germany. The key difference: liberals saw nationalism as a movement of the people; conservatives saw it as a tool of the state.", year:2020, marks:5, difficulty:"hard" },
  { title:"PYQ 2019", question:"What is Balkanism and how did the 'Eastern Question' contribute to the First World War?", answer:"Balkanism refers to the fragmentation of the Balkan peninsula as the Ottoman Empire declined and nationalist movements broke out among its subject peoples (Slavs, Greeks, Romanians, Bulgarians). The 'Eastern Question' was the European diplomatic problem of what to do with the decaying Ottoman Empire. How it led to WWI: (1) Austria-Hungary and Russia competed for influence in the Balkans. (2) Slavic nationalism, supported by Russia, threatened Austria-Hungary. (3) The assassination of Archduke Franz Ferdinand in Sarajevo in 1914 triggered a chain of alliances. (4) Each Balkan country tried to gain territory and independence, creating a powder keg. (5) Bismarck warned that 'some foolish thing in the Balkans' would cause the next great war — and he was correct.", year:2019, marks:5, difficulty:"hard" },
];

const ch1_easyMCQ = [
  { q:"The Frankfurt Parliament of 1848 was held in which building?", opts:["The Louvre","St Paul's Church","Notre Dame Cathedral","The Reichstag"], ans:1, exp:"The Frankfurt Parliament was held in St Paul's Church (Paulskirche) in Frankfurt. It was the first German national assembly, elected by popular vote, which tried to create a unified German constitution." },
  { q:"Who among the following unified Italy through 'Sword'?", opts:["Mazzini","Cavour","Garibaldi","King Victor Emmanuel II"], ans:2, exp:"Garibaldi provided the military sword — he led his famous army of volunteers called 'Red Shirts' who conquered southern Italy. Mazzini provided the ideology, Cavour the diplomacy, and Victor Emmanuel the leadership." },
  { q:"What was the 'Zollverein'?", opts:["A German parliament","A customs union removing tariff barriers between German states","A secret nationalist society","A religious union"], ans:1, exp:"Zollverein (1834) was a customs union created at Prussia's initiative that abolished tariff barriers between German states, unified the economy, and laid the groundwork for political unification." },
  { q:"Who was Frederic Sorrieu?", opts:["A German philosopher","A French artist who painted utopian visions of a democratic world","An Italian revolutionary","A Prussian general"], ans:1, exp:"Sorrieu was a French artist who created the famous 1848 paintings visualising a world of free democratic nations marching in fraternal procession — an early visual expression of nationalist utopian ideals." },
  { q:"The Romantic movement believed nationalism should be built on:", opts:["Military power and wars","Shared cultural heritage, emotions and history","Economic unions only","Scientific and rational principles"], ans:1, exp:"Romanticism reacted against pure rationalism and argued that true nationalism emerges from shared cultural bonds — language, folk tales, songs, art, and emotional attachment to the land and its history." },
  { q:"Who said 'When France sneezes, the rest of Europe catches cold'?", opts:["Napoleon","Metternich","Bismarck","Garibaldi"], ans:1, exp:"Metternich, the Austrian Chancellor, said this, acknowledging France's revolutionary influence on European politics. He feared that revolutionary ideas from France would destabilise conservative empires across Europe." },
  { q:"The German national anthem 'Das Lied der Deutschen' used the tune of a song composed by:", opts:["Beethoven","Wagner","Haydn","Bach"], ans:2, exp:"The German national anthem was set to a melody composed by Joseph Haydn. The nationalist movements used music powerfully — folk songs, anthems and operas became vehicles for expressing national identity." },
  { q:"In Sorrieu's 1848 painting, the people are marching before a symbol of:", opts:["The Cross","Liberty","Napoleon","The German Eagle"], ans:1, exp:"In Sorrieu's vision, the nations of Europe and America march before the statue of Liberty, symbolising his utopian vision of a free, democratic world organised into fraternal nation-states." },
  { q:"The concept of 'La Patrie' was introduced by the:", opts:["German Romantic movement","Napoleonic Code","French Revolution","Congress of Vienna"], ans:2, exp:"The French Revolution introduced concepts like 'La Patrie' (the fatherland) and 'le citoyen' (the citizen), creating a sense of collective national identity binding all French people as members of one community." },
  { q:"Which of the following was NOT a feature of the Napoleonic Code?", opts:["Equality before the law","Right to property","Restoration of feudal privileges","Abolition of serfdom"], ans:2, exp:"The Napoleonic Code abolished feudal privileges — it did NOT restore them. It established equality before law, secured property rights, and abolished serfdom and the guild system." },
  { q:"The symbol 'Germania' in German nationalism wore a crown made of:", opts:["Laurel leaves","Rose flowers","Oak leaves","Olive leaves"], ans:2, exp:"Germania wore a crown of oak leaves. The oak tree was the symbol of German strength and heroism. Combined with the tricolour and a sword, Germania embodied the aspirations of the German nationalist movement." },
  { q:"What was the 'Civil Code' introduced by Napoleon in 1804 also known as?", opts:["The Continental Code","The Napoleonic Code","The Paris Accord","The Vienna Charter"], ans:1, exp:"Napoleon's unified legal system established in 1804 is known as the Napoleonic Code. It became a model legal system adopted by many European countries and remains the basis of law in France today." },
  { q:"The Congress of Vienna (1815) was hosted by:", opts:["Prussia","France","Austria","Britain"], ans:2, exp:"The Congress of Vienna was hosted by Austria and dominated by Austrian Chancellor Klemens von Metternich. The conservative powers met to undo Napoleon's changes and restore the pre-revolutionary European order." },
  { q:"Young Italy was founded by:", opts:["Garibaldi","Cavour","Mazzini","Napoleon"], ans:2, exp:"Giuseppe Mazzini founded Young Italy — a secret revolutionary society that spread nationalist ideas and aimed to achieve Italian unity through popular uprising rather than diplomacy or military conquest." },
  { q:"Otto von Bismarck was the Chief Minister of which German state?", opts:["Bavaria","Austria","Prussia","Saxony"], ans:2, exp:"Otto von Bismarck was the Chief Minister (Chancellor) of Prussia, the most powerful German state. He used Prussian military might and diplomatic skill to unify Germany under Prussian leadership in 1871." },
];

const ch1_mediumMCQ = [
  { q:"Which of the following best explains why Napoleon's rule was a 'mixed blessing' for European peoples?", opts:["He brought peace but not trade","He spread revolutionary ideas but also imposed heavy taxes, censored press and forced military service","He only helped France, not other countries","He was kind to the nobility but cruel to commoners"], ans:1, exp:"Napoleon spread the revolutionary ideas of equality, rule of law and property rights through the Napoleonic Code. But he was also an imperial conqueror — he raised taxes, censored newspapers, and forced military conscription. This paradox made him both a liberator and an oppressor to different people." },
  { q:"The process by which German unification was achieved is best described as:", opts:["A democratic revolution from below by the liberal middle classes","Conservative unification from above through military power and state diplomacy","A religious crusade led by the Church","An economic process led by industrialists"], ans:1, exp:"Unlike the liberal Frankfurt Parliament's failed attempt at democratic unification (1848), German unification was achieved by Bismarck through 'blood and iron' — three wars and Prussian state power. This is called conservative unification 'from above' as opposed to revolutionary unification 'from below'." },
  { q:"Why did women participate in nationalist struggles but were denied political rights?", opts:["Women were not interested in politics","Men believed women lacked intellectual capacity","Nationalist movements were led by men who saw nationalism as a masculine project and excluded women from formal political participation","Women voluntarily chose not to participate"], ans:2, exp:"Women participated actively — founding political associations, running newspapers, marching in demonstrations. But male-dominated nationalist movements excluded them from political rights. At the Frankfurt Parliament, women could only sit in the galleries as observers. This contradiction — women fighting for a nationalism that denied them rights — is a key irony of the period." },
  { q:"What does the term 'Balkanisation' mean in the context of European history?", opts:["The process of industrialisation of the Balkans","The fragmentation of a region into smaller, hostile units based on ethnic/national lines","The economic integration of Balkan states","The Ottomanisation of Eastern Europe"], ans:1, exp:"Balkanisation refers to the fragmentation that occurred as nationalism broke up multi-ethnic empires (especially the Ottoman) into many small, often hostile states based on ethnic identity. The term is still used today for any process of fragmentation into small conflicting entities." },
  { q:"Which statement best describes the relationship between Cavour, Mazzini and Garibaldi in Italian unification?", opts:["They all used the same strategy of popular revolution","Mazzini provided ideology, Cavour provided diplomacy and alliances, Garibaldi provided military force","They competed against each other and never cooperated","Garibaldi was against unification"], ans:1, exp:"Italian unification succeeded because of the complementary roles: Mazzini's nationalist ideology created the dream; Cavour's diplomacy with France (against Austria) created the political conditions; Garibaldi's military campaigns unified the south. Without all three, unification would have failed." },
  { q:"The 1848 revolutions across Europe are described as a 'springtime of nations'. Why?", opts:["They happened during spring","They represented a brief, hopeful flowering of nationalist and liberal ideals that was quickly suppressed","They were caused by agricultural failures in spring","The revolutions succeeded permanently"], ans:1, exp:"'Springtime of nations' is a metaphor — the revolutions were like a spring bloom: sudden, beautiful and hopeful, but ultimately brief. By 1849, conservative forces had suppressed most revolutions. The metaphor captures both the hope of the moment and its tragic failure." },
  { q:"What was the significance of the oath taken at the Tennis Court (1789) for nationalism?", opts:["It was a sporting event","The French representatives swore not to disperse until they had given France a constitution — symbolising popular sovereignty over royal authority","It established the Napoleonic Code","It created the French army"], ans:1, exp:"The Tennis Court Oath represented the revolutionary principle that the representatives of the people (the nation) held sovereign power, not the king. This foundational act of popular sovereignty became the cornerstone of modern nationalism — the idea that the 'nation' is the source of political power." },
  { q:"Metternich's famous statement about nationalism being 'a disease' reflects:", opts:["His genuine medical concerns","His conservative fear that nationalism would break up the multi-ethnic Austro-Hungarian Empire","His opposition to France","His support for Italian unification"], ans:1, exp:"Austria-Hungary was a multi-ethnic empire containing Germans, Czechs, Slovaks, Hungarians, Italians, Poles and others. Nationalism threatened to break this empire apart along ethnic lines. Metternich correctly identified nationalism as existentially dangerous to empires like Austria — hence his determination to suppress it." },
  { q:"Why is the German unification of 1871 considered a 'revolution from above'?", opts:["It happened in the mountains","It was achieved by the Prussian state and military, not by popular democratic movements","It was supported by the German people","It was financed from foreign countries"], ans:1, exp:"'Revolution from above' means change imposed by the state rather than demanded by the people. Bismarck achieved unification through the Prussian state apparatus, military victories, and diplomatic manipulation — not through the liberal democratic movements that had failed in 1848. This left Germany with a strong state but weak democratic traditions." },
  { q:"What role did language play in building nationalism in 19th century Europe?", opts:["Language had no role — nationalism was purely political","Standardised national languages (through grammar books, dictionaries, literature) created a shared identity among people who had never met","Language was only important for education","Different languages prevented nationalism"], ans:1, exp:"Language was crucial. When people spoke the same standardised language, read the same literature, and sang the same songs, they felt connected to a common community — even if they lived in different places. The Romantic movement collected folk tales and folk songs, Grimm brothers standardised German, and newspapers spread the language — all creating national consciousness." },
  { q:"The 'Eastern Question' in European diplomacy referred to:", opts:["The problem of Russian expansion eastward into Asia","How to deal with the declining Ottoman Empire and the rise of Balkan nationalism","The trade routes to China and India","The religious conflicts in Eastern Orthodox Christianity"], ans:1, exp:"The Eastern Question was the complex diplomatic problem of what to do as the Ottoman Empire declined — which European power would control its former territories? This created conflict between Austria (which feared Slavic nationalism) and Russia (which wanted to protect Slavic peoples and gain access to warm-water ports)." },
  { q:"Greece achieved independence in 1829 through:", opts:["A peaceful negotiation with the Ottomans","A combination of armed struggle and European support from Britain, France and Russia","German military intervention","The Napoleonic Wars"], ans:1, exp:"Greek independence (1829) was achieved through years of armed struggle combined with crucial support from European powers. The Greek cause attracted romantics and liberals across Europe (including Byron who died there). This was the first successful nationalist movement in the Balkans and inspired others." },
  { q:"Which of the following is an example of 'liberalism' in the 19th century context?", opts:["Support for absolute monarchy","Belief in individual freedoms, constitutional government and free markets","Support for traditional feudal hierarchies","Opposition to free trade"], ans:1, exp:"19th century liberalism meant: individual rights (press, speech, religion), constitutional limits on government, elected representative assemblies, and free market economics. Liberals opposed absolute monarchy, feudal privilege, and state intervention in the economy. This is different from modern political 'liberalism'." },
  { q:"The unification of Italy was completed in 1871 when:", opts:["Venice was acquired in 1866","Rome was annexed after French troops withdrew following the Franco-Prussian War","Sicily was conquered by Garibaldi","The Papal States were dissolved"], ans:1, exp:"The final piece was Rome. The Papal States (including Rome) were protected by French troops. When Prussia defeated France in 1870-71 and French troops withdrew, Italy annexed Rome. Victor Emmanuel II entered Rome in 1871, completing unification. Rome became the new Italian capital." },
  { q:"ASSERTION: The 1848 revolutions failed because of social divisions within the nationalist movements. REASON: Liberal middle classes feared the radicalism of workers and peasants, leading them to compromise with conservative forces.", opts:["Both A and R true; R explains A","Both true but R doesn't explain A","A true, R false","A false, R true"], ans:0, exp:"This is a classic explanation of 1848's failure. When workers began demanding social reforms beyond nationalism (better wages, land reform, social equality), the middle-class liberals — who owned property and businesses — were frightened and withdrew their support. This social split allowed conservatives to crush the revolutions." },
];

const ch1_hardMCQ = [
  { q:"ASSERTION: Nationalism in Europe initially emerged as a product of the educated middle classes.\nREASON: Industrialisation created a prosperous middle class that sought political rights matching their economic status.", opts:["Both A and R true; R is correct explanation","Both true; R not the explanation","A true, R false","A false, R true"], ans:0, exp:"Both are correct and connected. The Enlightenment educated middle class (lawyers, teachers, merchants, artists) were the primary carriers of nationalist ideas. Their economic rise through industrialisation gave them the resources and confidence to demand political representation. Nationalism was initially an elite project that later became a mass movement." },
  { q:"CASE-BASED: A student argues that Napoleon was a 'liberator' of Europe. Another argues he was a 'conqueror'. Which position does the evidence in the chapter best support?", opts:["Only liberator — he spread revolutionary ideas everywhere","Only conqueror — he oppressed all countries","Both simultaneously — his conquest spread revolutionary changes but also imposed French dominance, creating a contradictory legacy","Neither — Napoleon had no lasting impact"], ans:2, exp:"The chapter explicitly presents Napoleon's dual legacy. He spread the Napoleonic Code (equality before law, property rights, end of serfdom) — genuinely liberating. Simultaneously, he raised taxes, imposed censorship, forced military service and treated conquered people as subjects not equals. Both are true simultaneously — this is the historical complexity students must grasp." },
  { q:"EXTRACT-BASED: 'An imagined community is one whose members will never meet but who nevertheless feel connected.' How does this concept apply to 19th-century European nationalism?", opts:["It doesn't apply — nationalists all knew each other personally","Newspapers, standardised languages, shared histories and symbols created bonds between strangers who felt they belonged to the same nation despite never meeting","Only applies to small communities","Applied only to France"], ans:1, exp:"This is Benedict Anderson's concept of 'imagined communities'. A German in Munich and one in Hamburg never met, but both read the same German newspapers, spoke the same standardised German, knew the same Grimm folk tales, and felt they belonged to 'Germany'. The nation is 'imagined' not because it's fake but because the community is too large for all members to know each other personally." },
  { q:"CASE-BASED: Why did European conservatives accept LIMITED nationalism after 1848 but rejected the radical liberal nationalism of 1848?", opts:["They began supporting democracy","They realised nationalism could strengthen existing states if controlled — Bismarck used nationalism to build a powerful unified Germany under Prussian conservative leadership","They feared France","Nationalism became economically profitable"], ans:1, exp:"After 1848, conservative leaders like Bismarck realised that nationalism could be harnessed for state power if it was divorced from liberal democracy. Bismarck's nationalism was conservative — it united Germany but created an authoritarian monarchy, not a democracy. This 'conservative nationalism' is fundamentally different from the liberal nationalism of 1848." },
  { q:"ASSERTION: The unification of Germany and Italy in 1871 marked the triumph of the Romantic nationalist ideal.\nREASON: Both were achieved through popular democratic revolutions as Mazzini and the Romantics had envisioned.", opts:["Both A and R true; R explains A","A true; R false — both were achieved through conservative state power and military force, not popular democratic movements","Both false","A false, R true"], ans:1, exp:"This is a critical distinction. The assertion is PARTIALLY true — Germany and Italy were unified. But the reason is false — they were NOT achieved through Mazzini's romantic vision of popular revolution. Both were achieved by conservative state machinery (Bismarck, Cavour). Ironically, the romantic nationalists' dream was fulfilled by the very conservative forces they opposed." },
  { q:"EXTRACT: 'Europe's map changed dramatically between 1815 and 1871. Nations were not always natural — they were constructed.' What does this mean?", opts:["Nations were built from building materials","National identities were deliberately created through symbols, education, language standardisation, and shared historical narratives — they did not pre-exist as natural categories","Nations formed naturally without human effort","The map was drawn incorrectly"], ans:1, exp:"This is the concept of 'constructivism' in nationalism. Nations are NOT natural, pre-existing entities waiting to be 'freed'. They are social constructions — created through deliberate acts of cultural production (Grimm brothers, national anthems, flags, school textbooks, museums, monuments). The 19th century saw intensive 'nation-building' where national identities were deliberately fabricated." },
  { q:"CASE-BASED: The Frankfurt Parliament offered the Crown of a united Germany to the Prussian King, who rejected it. What does this rejection reveal about the relationship between liberal nationalism and conservative monarchies?", opts:["The king was not German","The king feared war with Austria","Conservative monarchs would not accept legitimacy from popular assemblies — they believed their authority came from God and tradition, not from 'the people'","The crown was too heavy"], ans:2, exp:"Frederick William IV's rejection was ideologically principled: he called the parliament's offer a 'crown from the gutter'. For a conservative monarch, accepting power from elected commoners would mean acknowledging that his authority came from the people — destroying the divine right principle. This revealed the fundamental incompatibility between liberal popular sovereignty and conservative monarchism." },
  { q:"ASSERTION: Women's exclusion from the Frankfurt Parliament represents a fundamental contradiction within liberal nationalism.\nREASON: Liberal nationalism claimed to stand for universal rights and freedoms but in practice restricted these to men.", opts:["Both A and R true; R explains the contradiction","Both true but R doesn't explain it","A true, R false","Both false"], ans:0, exp:"This is the central feminist critique of 19th-century liberal nationalism. Nationalists spoke of 'the rights of man' and universal freedoms but excluded women from voting, holding office, and speaking at assemblies. Women who fought for nationalism — establishing political clubs, running newspapers, marching in protests — were then excluded from the fruits of that struggle. This contradiction would fuel the women's suffrage movement." },
  { q:"How did the decline of the Ottoman Empire create the conditions for the First World War?", opts:["The Ottomans started WWI","As the Ottoman Empire declined, multiple Balkan nations emerged competing for territory, drawing in Austria-Hungary and Russia — creating the flashpoint that triggered WWI at Sarajevo","The Ottomans allied with Germany to start the war","There is no connection between Ottoman decline and WWI"], ans:1, exp:"The causal chain: Ottoman decline → Balkan nationalism → new states competing for territory → Austria-Hungary (fearing Slavic nationalism) vs Russia (supporting Slavic peoples) → assassination of Franz Ferdinand in Sarajevo (1914) by a Bosnian Serb nationalist → chain of alliances → WWI. The Eastern Question was the long-term structural cause of WWI." },
  { q:"EXTRACT-BASED: 'Bismarck used wars as a diplomatic tool, not as ends in themselves.' What does this reveal about the nature of German unification?", opts:["Bismarck loved war","Bismarck's three wars were calculated, limited diplomatic manoeuvres to achieve specific political goals — not unlimited conquest — showing that German unification was a product of political strategy more than military adventure","Wars were accidental","Bismarck was a general not a politician"], ans:1, exp:"This is crucial to understanding Bismarck. Each war was precisely calibrated: against Denmark (to take Schleswig-Holstein), against Austria (to exclude Austria from German affairs), against France (to complete unification and humiliate France). He made peace quickly once objectives were achieved. This reveals unification as a product of cold political calculation — Realpolitik — rather than nationalist idealism." },
  { q:"CASE-BASED: A historian argues that 'nationalism destroyed the multi-ethnic empires of Europe but created new minority problems.' Evaluate this claim.", opts:["Nationalism only destroyed empires — no new problems created","True — as national states were created based on ethnic majorities, new minorities (ethnic, religious, linguistic) found themselves oppressed within the new nation-states, creating new problems","Nationalism solved all minority problems","Multi-ethnic empires were better for minorities"], ans:1, exp:"This is the tragic irony of nationalism: it claimed to free peoples from imperial oppression, but new nation-states created new minorities. When Germany unified, Poles in Prussia remained oppressed. When Greece gained independence, Muslims were expelled. When Balkan states formed, each had significant minorities who now faced the same oppression they had escaped. Nationalism solved one problem while creating another." },
  { q:"ASSERTION: The development of print culture was essential to the rise of nationalism.\nREASON: Printed materials in standardised national languages allowed people across a territory to share the same ideas, history and cultural references, creating a 'national consciousness'.", opts:["Both A and R true; R correctly explains A","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"This connects to Benedict Anderson's thesis. Print capitalism (newspapers, novels, pamphlets) in standardised languages was the technological foundation of modern nationalism. When thousands of people read the same newspaper in the same language, they began to think of themselves as a community sharing the same 'news'. Without printing, the mass national consciousness that made political nationalism possible could not have formed." },
  { q:"CASE-BASED: Why did the Balkan countries regard the Ottoman Turks as 'foreign rulers' despite centuries of shared history in the same territory?", opts:["Because of different food habits","Because nationalism redefined belonging in terms of ethnic/cultural/religious identity — making Ottoman rule 'foreign' despite its long presence — a concept that did not exist before nationalism", "Because the Turks spoke a different language only","Because of trade disputes"], ans:1, exp:"Before nationalism, people's primary identity was often religious (Christian vs Muslim) or local (city, village). Nationalism reframed identity as ethnic/national — suddenly the Ottoman Empire was 'Turkish' oppression of 'Greek', 'Serbian', 'Bulgarian' nations. This retrospective redefinition of 'foreign' and 'native' is how nationalism works — it creates a new lens through which all history is reread." },
  { q:"What is 'Realpolitik' and how did Bismarck use it to achieve German unification?", opts:["A philosophical theory about reality","A pragmatic approach to politics based on practical power considerations rather than ideology or moral principles — Bismarck used it to form temporary alliances, isolate opponents diplomatically, and wage limited wars to achieve specific goals","A type of German parliament","A military strategy"], ans:1, exp:"Realpolitik (practical politics) was Bismarck's method: no permanent friends or enemies, only permanent interests. He allied with Austria against Denmark, then turned against Austria, then allied with southern German states against France. He showed no loyalty to nationalist ideology — he used nationalism as a tool. This cold, calculating pragmatism achieved what the idealistic liberals of 1848 could not." },
  { q:"ASSERTION: The concept of the 'nation' as understood in 19th century Europe was closely linked to ideas of racial and cultural purity.\nREASON: Nationalist movements often excluded minority communities — Jews, Roma, linguistic minorities — who did not fit the dominant ethnic/cultural definition of the nation.", opts:["Both A and R true; R explains the darker side of A","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"This points to nationalism's dark side. The 19th-century 'nation' was often defined in exclusionary terms — true Germans were Protestant, spoke High German, traced ancestry to Germanic tribes. This excluded Jews (who spoke Yiddish), Polish speakers, Catholics in some contexts. The exclusionary logic of ethnic nationalism planted seeds that would grow into the extreme racial nationalism of the 20th century." },
  { q:"CASE-BASED: Compare the significance of the French Revolution (1789) and the revolutions of 1848 for European nationalism.", opts:["1848 was more important than 1789","1789 was only important for France","1789 established the foundational principles and ideals; 1848 tested those ideals across Europe but ultimately failed — together they define the trajectory of European nationalism from theory to practice and back to conservative reaction","Both had equal impact"], ans:2, exp:"1789 created the theoretical framework: popular sovereignty, citizen rights, the nation as political community. 1848 was the attempt to implement these ideas across Europe simultaneously — and its failure revealed both the power and the limits of liberal nationalism. The failure of 1848 drove the movement toward conservative nationalism (Bismarck, Cavour), changing the course of European history." },
];


