const ch4_pyqs = [
  { title:"PYQ 2023", question:"What is proto-industrialisation? How was it different from the factory system?", answer:"Proto-industrialisation refers to large-scale industrial production that occurred in the countryside BEFORE the factory system. It was based on a network of rural households producing goods for merchants. Key features: (1) Merchants supplied raw materials to rural artisans. (2) Products were collected by merchants who sold them in wider markets. (3) Production happened in homes, not factories. (4) Workers used their own tools and worked at their own pace. (5) It was driven by the expansion of European trade and colonial markets. Differences from the factory system: (1) No central location — scattered across villages. (2) No factory machines. (3) Workers were not 'employees' in the modern sense. (4) Less control over workers' time and methods. (5) Proto-industry allowed workers to combine farm work with craft production.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2023", question:"Why did industrialists in early Britain prefer hand technology over steam-powered machines in many industries?", answer:"This seems counterintuitive — industrialisation usually means machines. But early British industrialists had good reasons to prefer hand technology: (1) Labour was cheap — there was abundant cheap labour (including children and women) from enclosures and rural migration. (2) Machines required capital investment — merchants and manufacturers did not want to invest in machines when cheap labour was available. (3) Many products required fine craftsmanship that machines could not replicate — delicate luxury goods, custom orders for elite markets. (4) Seasonal industries — some industries (shipping, construction, gas works) had winter peak demand; hand workers could be hired and dismissed easily. (5) Machines sometimes created unemployment protests (Luddite movements) that damaged business. This is why Victorian Britain had millions of workers in traditional crafts alongside industrial factories.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What was the role of women workers in early industrialisation in Britain?", answer:"Women workers were central to early British industrialisation: (1) In textile mills — women and children were preferred because they could be paid less than men and were considered 'docile'. (2) In cotton mills — women operated spinning machines. (3) As domestic servants — the largest category of women's paid employment. (4) In the garment trade — seamstresses worked from home under piece-rate systems. (5) Wives of workers managed household budgets carefully. Challenges: (1) Women earned far less than men for the same work. (2) Women were excluded from skilled trades (regulated by guilds and later unions). (3) Factory work was dangerous and hours were extremely long. (4) Women's employment was considered temporary — they were expected to leave paid work when they married. The Factory Acts gradually regulated women's working hours, though these were sometimes resented as removing women's ability to earn.", year:2022, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"How did the colonial relationship between Britain and India affect Indian textile industries?", answer:"Britain's industrial capitalism systematically destroyed India's textile industries: (1) Indian textiles had dominated global markets before colonialism — Dhaka muslin, Surat cotton. (2) The British East India Company first used Indian textiles in trade, then from the 1820s, British machine-made cloth undercut Indian handloom. (3) Tariff discrimination — Indian textiles faced high tariffs entering Britain while British cloth entered India with minimal or no duty. (4) By 1850s, the global market for Indian handloom had largely collapsed. (5) Indian handloom weavers — millions of people — lost their livelihoods. (6) This de-industrialisation forced artisans into agriculture, increasing pressure on land. (7) The process was so devastating that some weavers reportedly cut off their own thumbs (a possibly apocryphal story symbolising the destruction of their craft).", year:2022, marks:5, difficulty:"hard" },
  { title:"PYQ 2021", question:"What were the Staple towns of Manchester and what was their role in the Industrial Revolution?", answer:"Manchester was the first industrial city in the world — the 'shock city' of the 1840s that amazed and horrified observers. Its role in industrialisation: (1) Centre of the cotton textile industry — the power loom and cotton spinning were fully mechanised here. (2) Manchester was connected to Liverpool by canal and later railway — the raw cotton came in from American slave plantations via Liverpool; finished cloth went out worldwide. (3) Manchester became a symbol of the new industrial order — with factories, slums, child labour and industrial pollution. (4) It was also a centre of radical politics — the Chartist movement, trade unionism, and the Anti-Corn Law League all had major Manchester presences. (5) Manchester's free trade ideology ('the Manchester School') shaped British economic policy.", year:2021, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"Describe the life of a cotton mill worker in early 19th century Britain.", answer:"The life of a cotton mill worker was harsh: (1) Working hours — typically 14-16 hours per day, 6 days a week. Children as young as 5 or 6 worked. (2) Wages — extremely low, barely enough for survival. (3) Factory conditions — deafening noise, cotton dust causing 'brown lung' disease, dangerous machinery causing injuries and deaths. (4) Factory discipline — strict — workers were fined for arriving late, singing, or leaving their machines. 'Overlookers' enforced discipline with physical punishment. (5) Housing — workers lived in overcrowded slums near factories — no sanitation, disease was rampant (cholera, typhus). (6) Child labour — children performed tasks adults couldn't fit into — crawling under machines, working as 'scavengers' picking up loose cotton. (7) Food — poor diet, limited variety. The Factory Acts (from 1833) gradually improved conditions — limiting children's hours, requiring basic education.", year:2021, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"What was the Bombay cotton mill industry and how did it develop?", answer:"The Bombay cotton textile industry was India's first major mechanised industry: (1) First cotton mill established in 1854 by Cowasji Davar — a Parsi businessman. (2) By 1900, Bombay had 84 mills employing 150,000 workers. (3) Raw cotton was grown in Gujarat and the Deccan — easily available. (4) Indian mill owners produced coarser cloth that could compete with British imports. (5) Finer British cloth retained market dominance for longer. (6) Indian mills employed women from lower castes and poor families. (7) Working conditions were exploitative — long hours, low wages, dangerous machinery. (8) The First World War boosted Indian mills — they supplied cloth to the army when British imports were reduced. (9) After WWI, Indian industrialists began organising politically — the Bombay mill owners' associations supported the Congress movement.", year:2020, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"How did advertisements and labels change the relationship between producers and consumers during industrialisation?", answer:"Industrialisation produced mass goods that needed mass markets. Advertisements and labels were crucial: (1) Before industrial production, consumer goods were bought locally and knew their maker personally. Industrial goods needed brand identity. (2) Labels and trade marks (like the 'Swadeshi' symbols or Manchester's 'Indian' imagery) told consumers what the product was and where it came from. (3) Manchester manufacturers put images of Indian gods, portraits of Indian leaders, and scenes of Indian life on their labels to appeal to Indian consumers — 'calico' prints designed for colonial markets. (4) Calendar art — Indian manufacturers used images of nationalist icons, religious figures and film stars on calendars to advertise products. (5) Advertisements promised that products would bring prosperity, respectability, or patriotism. (6) The Swadeshi movement used advertisements to promote Indian goods as patriotic purchases.", year:2020, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"What is the significance of the Elbe and Rhine in the context of European industrialisation?", answer:"The Elbe and Rhine are major European rivers. Their significance for industrialisation: (1) The Rhine carried coal from the Ruhr valley (Germany's industrial heartland) to industrial cities. (2) Rivers provided water power for early mills. (3) Canals connected rivers to create internal waterway networks that transported heavy industrial goods before railways. (4) River-based transport was far cheaper than road transport for heavy goods (coal, iron, grain). (5) Industrial cities often grew at river confluences — where transport routes met. The geography of rivers largely determined where industrial cities grew in 18th-19th century Europe.", year:2019, marks:2, difficulty:"easy" },
  { title:"PYQ 2019", question:"How did the calico printing industry in India and the Indian Ocean trade network change after British colonialism?", answer:"Pre-colonial India was a major producer of printed cotton textiles (calico) for global markets via Indian Ocean trade. Colonial transformation: (1) Indian calico printers supplied cloth to East Africa, Southeast Asia and the Middle East through Arab and Indian merchant networks. (2) British merchants first traded in Indian calico, then began copying Indian designs for European markets. (3) From 1720s-1760s, British manufacturers lobbied Parliament to ban Indian calico imports to protect their own industry. (4) British cotton textiles adopted Indian designs and patterns (chintz, paisley, calico prints) — effectively appropriating Indian aesthetic traditions for British commercial advantage. (5) The global market that Indian weavers had built was captured by British imitators using machines. This is one of the most striking examples of how colonial economics worked — appropriating knowledge while destroying its creators.", year:2019, marks:3, difficulty:"medium" },
  { title:"PYQ 2023", question:"How did India's role in the global economy change between the 18th and 19th centuries?", answer:"Dramatic reversal: (1) 18th century — India was a major exporter of manufactured goods (textiles, ships, metalwork). Indian textiles dominated global markets. India's share of world manufacturing was 25% in 1750. (2) 19th century under colonialism — India became primarily an exporter of raw materials (cotton, jute, tea, opium) and an importer of British manufactured goods. (3) India's share of world manufacturing fell to 2% by 1900. (4) Indian artisans (weavers, ship-builders, metalworkers) lost global markets. (5) New industries emerged under colonial conditions — indigo, opium, tea plantations — but these served colonial needs not Indian development. (6) The railway network (built with Indian revenues) connected agricultural areas to ports for exporting raw materials, not for Indian industrial development.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What was the impact of the First World War on Indian industries?", answer:"WWI (1914-18) gave Indian industries an unexpected boost: (1) British cloth imports to India fell sharply — British mills converted to war production. (2) Indian cotton mills captured the market British mills had vacated. (3) Indian jute mills supplied sandbags for the trenches. (4) Tata Iron and Steel produced steel for the war effort. (5) Indian industry expanded rapidly — new mills established, production increased. (6) The Indian government reversed some of its anti-industrial bias — tariffs were allowed. (7) Indian industrialists accumulated capital during WWI. However: (1) After the war, British cloth returned and Indian mills faced competition again. (2) The post-war boom was followed by recession. (3) But the industrial capacity created during WWI gave India a stronger industrial base for future development.", year:2022, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"How did the experience of Indian weavers change during the 19th century?", answer:"Indian weavers' experience: (1) In the early 19th century, British demand for Indian raw cotton increased — but this raised raw material prices for weavers who also needed cotton. (2) When the American Civil War (1861-65) cut off American cotton to Britain, British demand for Indian cotton skyrocketed — prices rose dramatically, making raw cotton unaffordable for Indian weavers. (3) After the war, the cotton glut and falling prices hurt farmers who had shifted to cotton. (4) Simultaneously, British machine-made cloth was flooding Indian markets at prices Indian handloom couldn't match. (5) Some weavers specialised in finer cloth that machines couldn't replicate. (6) Some adapted — weaving new patterns, entering new markets. (7) Many were destroyed — forced into agriculture or other low-wage work. The diversity of responses shows that the impact of colonialism was not monolithic.", year:2021, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"What was the role of merchants and bankers in Indian industrialisation?", answer:"Indian merchants and bankers played crucial roles: (1) Precolonial — Indian merchants dominated trade networks across Indian Ocean, Central Asia and the Persian Gulf. Rich merchant communities like the Marwaris, Chettiars, Parsis accumulated capital. (2) Colonial transition — some merchant communities adapted to the new colonial economy by working with British firms, financing internal trade, money-lending. (3) Financing industry — the first Indian cotton mills (Bombay 1854) were financed by Parsi merchants who had prospered in colonial trade (especially the opium trade). (4) Marwari merchants from Rajasthan spread across India as traders and moneylenders, and later (20th century) became major industrialists (Birlas). (5) Bankers provided the credit that allowed both agricultural and industrial enterprises to operate. (6) Merchant capital was the necessary precondition for industrial capital.", year:2020, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"How did the factory system change the nature of labour?", answer:"The factory system fundamentally transformed labour: (1) Time — workers had previously worked according to natural rhythms (season, daylight). Factory work imposed clock-time — specific hours, penalties for lateness. (2) Location — work moved from home/workshop to the factory — separating 'work' from 'home' for the first time. (3) Supervision — factory overseers constantly supervised workers — replacing the autonomy of the artisan or farmer. (4) Skill — factories often de-skilled labour — a weaver's lifetime of skill was replaced by one task in an assembly line. (5) Wages — factory workers depended entirely on wages for survival — unlike farmers who grew food or artisans who sold directly. (6) Collective — factories brought thousands of workers together, creating the conditions for trade unionism and collective action. (7) Discipline — factory discipline through fines, docked wages and physical punishment was a new form of control.", year:2019, marks:5, difficulty:"hard" },
];

const ch4_easyMCQ = [
  { q:"Proto-industrialisation refers to:", opts:["The first factories in Britain","Large-scale industrial production in rural homes before the factory system","Industrial production in cities","Small scale urban artisan production"], ans:1, exp:"Proto-industrialisation was the system where merchants supplied raw materials to rural households who produced goods (especially textiles) at home. It preceded the factory system and represented large-scale production without central factories or machines." },
  { q:"The first major industry of the Industrial Revolution in Britain was:", opts:["Iron and steel","Coal mining","Cotton textiles","Shipbuilding"], ans:2, exp:"Cotton textiles were the first industry to be fully mechanised in Britain — the spinning jenny, water frame, power loom, and cotton gin transformed cotton production. Manchester became the world's first industrial city around this industry." },
  { q:"The Spinning Jenny was invented by:", opts:["James Watt","Richard Arkwright","James Hargreaves","Edmund Cartwright"], ans:2, exp:"James Hargreaves invented the Spinning Jenny around 1764. It allowed one worker to spin multiple threads simultaneously, dramatically increasing productivity. The name 'jenny' may come from Hargreaves' wife or daughter." },
  { q:"What is 'de-industrialisation' in the Indian context?", opts:["Building new industries","The decline of India's traditional industries due to British competition and colonial policies","Industrial pollution in India","Moving industries from cities to villages"], ans:1, exp:"De-industrialisation refers to how British colonialism destroyed India's pre-existing manufacturing industries. Indian textiles (which had dominated global markets) were undercut by British machine-made cloth supported by tariff discrimination — destroying millions of artisan livelihoods." },
  { q:"The first cotton mill in India was established in Bombay by:", opts:["Jamsetji Tata","Dinshaw Wacha","Cowasji Nanabhoy Davar","Jamsetji Jejeebhoy"], ans:2, exp:"Cowasji Nanabhoy Davar, a Parsi businessman, established the first cotton mill in Bombay in 1854. He returned from a visit to Manchester inspired by what he had seen and set up the Bombay Spinning and Weaving Company." },
  { q:"What was the 'putting out' system in the context of proto-industrialisation?", opts:["A system of firing workers","Merchants putting out raw materials to rural workers and collecting finished products","Putting goods out for sale directly","Exporting goods out of the country"], ans:1, exp:"The 'putting out' system was the defining feature of proto-industrialisation: a merchant would 'put out' raw materials (wool, cotton) to rural workers who processed them at home, then 'put out' the finished goods to the merchant. It was a merchant-controlled production system without factories." },
  { q:"The Luddites were:", opts:["Supporters of industrialisation","Workers who destroyed machines because they feared losing their jobs to technology","Factory owners","Government inspectors"], ans:1, exp:"Luddites (1811-16) were skilled textile workers in England who broke machines (power looms, knitting frames) that were replacing them. Named after a mythical Ned Ludd who supposedly smashed two stocking frames. They weren't anti-technology but feared (correctly) that machines would destroy their skilled, well-paid livelihoods." },
  { q:"What did 'calico' originally refer to?", opts:["A type of pottery","Cotton cloth imported from India, particularly from Calicut (Kerala)","A painting style","A French fashion"], ans:1, exp:"Calico originally referred to cotton cloth imported to Europe from Calicut (Kozhikode), Kerala — hence the name. Indian printed calico was hugely popular in Europe (17th-18th century). European manufacturers lobbied to ban Indian calico imports to protect their industries, then began manufacturing their own." },
  { q:"The East India Company began as a:", opts:["Cotton mill","Government department for India","Trading company interested in spice and cloth trade","Military organisation"], ans:2, exp:"The East India Company (founded 1600) was originally a trading company — its charter gave it monopoly rights on English trade with the East Indies. It traded in spices, cotton, silk, tea and opium. It only gradually acquired territorial control over India from the 1750s." },
  { q:"What were the Gomasthas in the East India Company's procurement system?", opts:["Indian soldiers","Paid servants of the Company who supervised weavers and ensured supply","Indian merchants competing with the Company","Village headmen"], ans:1, exp:"Gomasthas were paid agents appointed by the East India Company to supervise the weaving villages. They replaced local merchants, paid weavers in advance (creating debt), inspected cloth quality, and ensured exclusive supply to the Company — effectively tying weavers to the Company." },
  { q:"Who wrote 'Hard Times' — a novel depicting industrial England?", opts:["Charles Dickens","Jane Austen","Thomas Hardy","George Eliot"], ans:0, exp:"Charles Dickens wrote Hard Times (1854), depicting the grimness of industrial Coketown — based on Manchester/Preston. Dickens's novels (also Oliver Twist, Bleak House) depicted the social costs of industrialisation — child labour, poverty, workhouses — and were powerful critiques of industrial capitalism." },
  { q:"By 1900, the majority of India's cotton mills were concentrated in:", opts:["Calcutta","Madras","Bombay and Ahmedabad","Delhi"], ans:2, exp:"The cotton textile industry concentrated in Bombay and Ahmedabad in western India — close to raw cotton production in Gujarat and the Deccan. Calcutta's industries were more jute-focused. By 1900, Bombay had 84 mills employing 150,000 workers." },
  { q:"What is 'piece-rate' work?", opts:["Work in the factory","Workers paid a fixed salary","Workers paid for each unit they produce rather than per hour — common in 19th century home-based industry","Working in pieces of time"], ans:2, exp:"Piece-rate (or piecework) means payment per unit produced rather than per hour. It was common in proto-industry and home-based sewing, lacemaking, and similar trades. It gave employers flexibility (no obligation to employees when orders were slow) but left workers vulnerable to income fluctuations." },
  { q:"The Tata Iron and Steel Company was founded in:", opts:["1868","1907","1885","1919"], ans:1, exp:"Jamsetji Nusserwanji Tata laid the foundations for TISCO (Tata Iron and Steel Company) — it was formally established by his sons in Jamshedpur in 1907. Jamsetji died in 1904 without seeing it completed. TISCO was the first large-scale indigenous steel plant in India." },
  { q:"Why was child labour common in early British factories?", opts:["Children were more productive than adults","Factories employed children because they could be paid much less, could fit into small spaces (like chimneys and under machines), could be controlled more easily, and were available in large numbers from workhouses","Children preferred factory work","The government required children to work"], ans:1, exp:"Child labour in early industrialisation was driven by economics: children's wages were a fraction of adults'. Young children ('climbing boys') swept chimneys; factory children called 'scavengers' retrieved cotton waste under running machines. Workhouses supplied children cheaply. The Factory Act 1833 began restricting child labour by requiring minimum age (9) and limiting hours." },
];

const ch4_mediumMCQ = [
  { q:"Why did early industrialisation concentrate in certain regions rather than spreading uniformly?", opts:["Government planned it to be in certain areas","Certain regions had coal, iron ore, rivers for power, and pre-existing craft traditions — creating geographic clustering of industries","Industrialisation spread equally everywhere","Climate determined industrial location"], ans:1, exp:"Industrial geography was determined by resource endowments: (1) Coal — industries clustered near coal fields (Yorkshire, Lancashire, Ruhr in Germany). (2) Iron ore — near iron deposits. (3) Rivers — for water power and transport. (4) Existing craft skills — cotton mills in Lancashire because there was already a tradition of handloom weaving. (5) Ports — access to raw material imports and export markets. These factors created industrial regions (Manchester, Birmingham, Glasgow) and left other regions rural." },
  { q:"How did the enclosure movement contribute to the Industrial Revolution in Britain?", opts:["Enclosures had no effect on industrialisation","Enclosures created industrial workers by forcing peasants off common land — creating a landless labour force dependent on wages that factory owners needed","Enclosures were an industrial process","Enclosures helped farmers not factories"], ans:1, exp:"Enclosures (Parliamentary Enclosure Acts, especially 18th century) fenced off common lands that peasants had used collectively for grazing and gathering. Dispossessed peasants streamed into cities looking for work — providing the cheap labour that industrial capitalism needed. This 'primitive accumulation' of labour was as important to industrialisation as the machines themselves." },
  { q:"What is the significance of the American Civil War (1861-65) for Indian cotton weavers?", opts:["It had no impact on India","The civil war directly caused Indian independence","When the US civil war disrupted American cotton exports to Britain, British demand for Indian cotton rocketed — raising raw cotton prices dramatically, which benefited Indian cotton farmers but devastated Indian weavers who could no longer afford raw material","The civil war caused Indian industrialisation"], ans:2, exp:"This is a perfect example of how global interconnection creates complex, unequal effects. American cotton prices collapsed (war cut southern exports) → Britain turned to India → Indian raw cotton prices soared → Indian cotton FARMERS benefited → but Indian WEAVERS were crushed as they could no longer afford raw material. After the war, cotton glut and falling prices hurt farmers who had expanded production. The same global event helped and hurt different Indian groups simultaneously." },
  { q:"Why did Indian industrialists often struggle against European business firms in colonial India?", opts:["Indian industrialists were less skilled","Indian industrialists faced structural disadvantages: colonial law favoured European firms; government contracts went to Europeans; access to credit was easier for Europeans; tariff policies sometimes protected European imports from Indian competition","Indians chose not to compete","Europeans were more hardworking"], ans:1, exp:"Colonial India maintained structural advantages for European capital: (1) Exchange banks were owned by Europeans. (2) Government contracts favoured European firms. (3) The colonial state sometimes imposed tariffs protecting British imports against Indian competition. (4) European firms had advantages in overseas finance. Indian industrialists succeeded despite these obstacles by focusing on sectors (cotton, jute) where geography gave them raw material advantages." },
  { q:"How did the role of the East India Company change from the 18th to 19th century?", opts:["It remained purely a trading company throughout","From a trading company focused on Indian textiles for world markets, it transformed into a colonial ruler extracting taxes and raw materials for British industry","It became a nationalist organisation","The Company expanded its trading activities"], ans:1, exp:"The transformation was dramatic. 18th century EIC: traded Indian textiles to European and Asian markets — India's manufacturing powered the Company's profits. 19th century EIC (after becoming colonial ruler): the Company taxed India's territory, used revenues to buy Indian raw materials, and facilitated the flooding of India with British manufactured goods. From promoting Indian manufacturing to destroying it — driven by British industrial interests." },
  { q:"What does the term 'putting out' system reveal about the power relationship between merchants and artisans?", opts:["Artisans had full control","Merchants and artisans were equal partners","Merchants controlled capital (raw materials), credit, and market access — giving them structural power over artisans who appeared to work independently but were actually dependent and controlled","Artisans were more powerful than merchants"], ans:2, exp:"The 'putting out' system appears to leave artisans in control of their work process, but merchants controlled all the essential elements: they owned the raw materials, provided advance credit (creating debt dependency), had market knowledge and connections, and could refuse to collect finished goods. Artisans who tried to sell independently or work for competitors could be cut off from materials and credit. This is 'formal freedom with material dependence'." },
  { q:"How did the Swadeshi Movement influence advertising and consumption patterns in colonial India?", opts:["Swadeshi had no effect on consumption","Swadeshi created a political culture of consumption — choosing Indian-made goods became an act of patriotism, and advertising using nationalist imagery (Gandhi's image, Hindu symbols, Indian scenes) became a way of distinguishing Indian products from British ones","Swadeshi only affected politicians","Swadeshi banned all advertising"], ans:1, exp:"The Swadeshi movement transformed advertising from commercial to political. Indian manufacturers used calendar art with nationalist heroes, religious imagery and 'Made in India' labels to appeal to consumers' patriotism. A British-made cloth was not just an economic choice but a political one — choosing it supported colonial exploitation; choosing Indian cloth was a small act of resistance. This politicisation of consumption is a uniquely colonial-nationalist phenomenon." },
  { q:"What were the working conditions in Bombay cotton mills like in the early 20th century?", opts:["Excellent — Indian factories were better than British","Not documented — we have no information","Harsh — long hours (12-15 per day), dangerous machinery, cotton dust causing lung disease, low wages, strict supervision, no job security — similar to early British industrial conditions","Workers were very well paid"], ans:2, exp:"Indian factory conditions in the early 20th century mirrored early British industrialisation: 12-15 hour days; 6 day weeks; young children working; no compensation for injuries; cotton dust causing 'byssionosis' (brown lung); strict discipline. Trade unions gradually developed after WWI. The Bombay Industrial Relations Act and subsequent legislation gradually improved conditions, but the early period was exploitative." },
  { q:"Why is the Industrial Revolution considered a 'revolution' despite happening gradually over decades?", opts:["It wasn't really a revolution","It was called a revolution for political reasons","The cumulative transformation of the economy, society and environment was so profound — from agrarian to industrial, rural to urban, craft to factory — that despite its gradual pace, it fundamentally changed everything about human life, justifying the word 'revolution'","It happened very quickly"], ans:2, exp:"The 'revolutionary' nature of industrialisation is not speed but depth. Within 100 years: Britain went from 80% rural to 80% urban; from hand craft to mechanised production; from domestic to international economy; from aristocratic to bourgeois power; from subsistence to wage labour. The environmental, social and economic transformation was more profound than any political revolution. The word 'revolution' captures its totality, not its pace." },
  { q:"What is the significance of the Manchester 'school of thought' (free trade ideology) for colonial India?", opts:["Manchester ideas helped India","Manchester free trade ideology conveniently argued that Britain's interests (opening all markets to British goods) were universal economic laws — making colonialism look like enlightened economics rather than exploitation","Manchester thought had no impact on India","Manchester industrialists supported Indian industries"], ans:1, exp:"The 'Manchester school' (Cobden, Bright) argued that free trade was universally beneficial — all countries should specialise in what they produce most efficiently and trade freely. For India, this meant: export raw cotton, import British cloth. For Manchester mill owners: this was self-servingly convenient economics dressed as universal law. Colonial India was forced into free trade that served British manufacturing interests while destroying Indian industry." },
  { q:"How did the First World War change the relationship between the Indian colonial government and Indian industry?", opts:["The war had no effect on this relationship","The war forced the colonial government to partially reverse its anti-industrial bias — allowing tariff protection and stimulating Indian production for the war effort — establishing that Indian industrial capacity was in British imperial interest","The war destroyed all Indian industry","The government gave India complete economic independence during the war"], ans:1, exp:"WWI created a paradox: Britain needed Indian industrial production (jute bags for sandbags, steel, cloth for uniforms) but the colonial policy had been to prevent Indian industrial competition with British firms. The war forced pragmatic support for Indian industry. The post-war 'fiscal autonomy convention' (1919) gave India some ability to impose protective tariffs for the first time. This was a significant shift — showing that Indian industrialisation was compatible with imperial interests when those interests required it." },
  { q:"What is meant by the 'labour aristocracy' in early industrial Britain?", opts:["Factory owners who were aristocrats","Skilled male workers (like engineers, printers, pattern-weavers) who earned higher wages, maintained craft traditions, ran trade unions and had cultural authority within the working class","Aristocrats who worked in factories","Women workers who earned more than men"], ans:1, exp:"The labour aristocracy was a distinctive upper layer of the working class: skilled craftsmen who commanded higher wages because of non-replaceable skills; often organised in exclusive craft unions; owned their homes, wore suits, read newspapers. They distinguished themselves from unskilled factory workers and often had conservative political views. The distinction between 'skilled' and 'unskilled' labour was central to 19th-century working-class culture and politics." },
  { q:"How did Indian artisans adapt to the decline of their traditional markets in the 19th century?", opts:["All artisans gave up their crafts","Artisans refused to adapt","Some adapted — specialising in finer goods machines couldn't replicate, finding new markets (pilgrimage sites, local celebrations), entering new occupations, or migrating to cities. Others were crushed and forced into agricultural labour. The diversity of responses shows individual agency within structural constraint","All artisans became factory workers"], ans:2, exp:"Historical research shows that artisan responses were varied and creative: weavers in Varanasi specialised in fine silk that handlooms produced better than power looms; Dhaka weavers developed new lighter muslin for hot weather; some communities migrated to cities to work in new industries or services. But many could not adapt — the structural forces were too powerful. This diversity of outcomes warns against over-determining economic history as inevitable decline." },
  { q:"What was the significance of Jamshedpur as an industrial site?", opts:["It was chosen randomly","Tata chose Jamshedpur (Bihar-Jharkhand border) because it was near iron ore deposits (Jharia), coal fields (Jharia coalfield), rivers (Subarnarekha), and railway connections — demonstrating that Indian industrialisation was guided by the same resource-logic as British industrialisation","Jamshedpur was chosen for political reasons","It had no natural advantages"], ans:1, exp:"Jamshedpur's selection shows Tata's industrial planning was sophisticated. Jamsetji Tata himself identified the Sakchi site (later Jamshedpur) based on proximity to raw materials. The presence of iron ore, limestone, and coal nearby, plus river water and rail connectivity, made it optimal. The city that grew around the TISCO plant became a planned industrial city — Jamshedpur — one of India's most interesting urban experiments." },
  { q:"How did the experience of Indian mill workers compare with British factory workers of the same period?", opts:["Indian workers had better conditions","Both experienced similar harsh conditions — long hours, dangerous machinery, low wages, strict discipline — but Indian workers faced additional discrimination based on caste, gender and ethnicity within the mill hierarchy","British workers had worse conditions","Indian workers were not exploited"], ans:1, exp:"The comparison reveals the universality of early industrialisation's harshness while highlighting specifically colonial-Indian dimensions. Caste discrimination within mills (high-caste workers refused to work with Dalits; caste-based job hierarchies); ethnic divisions (Marathi vs UP workers; Hindu vs Muslim); gender discrimination (women in lower-paid categories) — all added colonial social hierarchies to the universal experience of industrial exploitation." },
];

const ch4_hardMCQ = [
  { q:"ASSERTION: Proto-industrialisation shows that industrial capitalism existed before factories.\nREASON: The key feature of capitalism — merchant control of production, capital investment, market-oriented output — was present in putting-out systems centuries before factory machinery.", opts:["Both A and R true; R correctly explains A","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. Proto-industrialisation challenges the standard narrative that capitalism begins with factories. Merchants who organised putting-out systems already had capital, controlled production, and sold in markets. The factory only changed the location of production and intensified control — the capitalist RELATIONSHIP of production predated industrial technology. This insight changes how we understand capitalism's origins." },
  { q:"CASE-BASED: A student argues that the Industrial Revolution improved living standards for everyone. How would a social historian respond?", opts:["The historian would agree completely","The historian would disagree completely — industrialisation was uniformly bad","The historian would provide a nuanced view: living standards improved long-term and on average, but this average concealed severe short-term misery for displaced artisans, child labourers, and urban slum dwellers; gains were distributed very unequally by class, gender and geography","Living standards immediately improved for all workers"], ans:2, exp:"The 'standard of living debate' in economic history remains alive. Real wages did rise (on average, eventually). But: (1) Short-term (1780-1840) living standards for many workers fell as handcraft was destroyed. (2) Average improvement concealed massive inequality — millowners became enormously wealthy while workers lived in slums. (3) Child labour, dangerous conditions, urban disease. (4) Women's wages far below men's. The question 'improved for whom?' reveals that aggregate economic growth and equitable distribution are different things." },
  { q:"EXTRACT-BASED: 'The factory system did not just change how goods were made — it changed what it meant to be a worker.' Explain.", opts:["The factory only changed production technology","Workers' identities were unaffected by the factory system","True — the factory system transformed the nature of work: from autonomous skilled craftsman to supervised wage-worker; from home-based to factory-based; from setting own pace to clock-discipline; from multi-skilled to single-task. This was a profound identity change — workers went from 'master of their craft' to 'hands' in someone else's machine","Only urban workers were affected"], ans:2, exp:"This is the 'proletarianisation' thesis in labour history. Pre-industrial weavers and artisans had craft pride, controlled their time, knew the whole process, and sold directly. Factory workers became 'hands' — a dehumanising term revealing how industrial capitalism reduced human beings to body parts in a machine. This loss of craft autonomy and identity was what the Luddites and early labour movement was partly about — not just wages but dignity and control." },
  { q:"ASSERTION: India's failure to industrialise in the 19th century was not inevitable but was a product of deliberate colonial policy.\nREASON: Indian merchants had capital, traditional craft skills existed, raw materials were abundant — the missing element was tariff protection and state support that colonial rule deliberately withheld.", opts:["Both A and R true; R explains why colonialism mattered for industrialisation","Both true but unconnected","A true, R false — India lacked capital","A false — India could not have industrialised anyway"], ans:0, exp:"This is one of the central arguments in economic history of colonialism. The counterfactual matters: Germany, USA, Japan all industrialised with state protection when their industries were less efficient than British ones. India had merchant capital (Marwaris, Parsis), craft skills, and raw materials — but colonial policy denied tariff protection while forcing open India's markets to British goods. When some protection was allowed (post-1919), Indian industry expanded. The argument that colonialism prevented Indian industrialisation has strong evidence." },
  { q:"CASE-BASED: How does the story of Indian indigo cultivation under the colonial putting-out system illustrate the power relations of proto-industrialisation?", opts:["Indigo cultivation was voluntary and fair","Indian farmers freely chose to grow indigo","The tinkathia system forced Indian farmers to grow indigo on 3/20ths of their land for British planters at fixed prices — British planters controlled capital, land leases and market access, reducing nominally 'free' Indian farmers to indentured cultivators in all but name. This was proto-industrialisation's dark side — merchant/planter control without any workers' rights","Indigo cultivation benefited Indian farmers"], ans:2, exp:"The indigo system in Bihar and Bengal was a colonial variant of proto-industrialisation: British planters advanced money (creating debt), forced cultivation through lease agreements, bought indigo at prices set by themselves, and used physical violence against farmers who resisted. Gandhi's Champaran Satyagraha (1917) was specifically about this system. It shows how 'freedom' in market relations can coexist with actual coercion when one party controls capital, land, and law." },
  { q:"EXTRACT: 'Manchester built its industrial wealth partly by appropriating Indian aesthetic traditions.' Evaluate.", opts:["Manchester created its own original designs","There was no cultural exchange between India and Britain","British calico printers copied Indian patterns (chintz, paisley, geometric designs) that had been developed over centuries by Indian craftspeople, reproduced them by machine, and undersold them in markets including India — appropriating Indian cultural creativity for British commercial advantage","Indian designs were not used in Manchester"], ans:2, exp:"This is cultural appropriation in economic history. Indian printed cotton (chintz, calico) was hugely popular in 17th-18th century Europe. British textile manufacturers first lobbied Parliament to ban Indian imports (1690-1721) to protect themselves, then copied Indian patterns by machine. 'Paisley' is a Scottish town that mass-produced an Indian design (the boteh pattern). Selling machine-copies of Indian designs back to India at prices Indian handloom couldn't match is economic irony of the first order." },
  { q:"ASSERTION: The rise of Bombay as India's industrial centre reflected both colonial geography and community enterprise.\nREASON: Bombay's geographic location as a cotton-growing hinterland port, combined with Parsi and Marwari entrepreneurship, made it India's industrial capital despite colonial obstacles.", opts:["Both A and R true; R explains the specific conditions enabling Bombay's rise","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Bombay's industrialisation resulted from the intersection of geography and community. Location: close to Gujarat's cotton fields; major port for imports/exports. Community: Parsi merchants had accumulated capital in colonial trade (including the morally complex opium trade); their social position as religious minorities paradoxically freed them from some caste constraints and oriented them toward commerce; they were culturally exposed to Western ideas through colonial contact. Cowasji Davar, Jamsetji Tata — both Parsi. Geography plus social capital = Bombay's industrial success." },
  { q:"CASE-BASED: Compare the development of the cotton textile industry in Britain and India in the 19th century. What does the comparison reveal about colonialism?", opts:["Both industries developed similarly","India's industry was more advanced","Britain's cotton industry mechanised with state tariff protection and became globally dominant. India's pre-existing cotton tradition was systematically destroyed through colonial tariff policy, then a new machine-based industry emerged despite rather than because of colonial rule. The comparison reveals that industrialisation is not natural but political — it requires state support that colonialism denied to India while providing to Britain","Industrialisation happens automatically without state support"], ans:2, exp:"The comparison is devastating for free-market development theory. Britain protected its cotton industry in its early stages (various Navigation Acts, tariffs on Indian calico). Having achieved dominance through protection, Britain then demanded free trade — removing the ladder it had used to climb. India was denied the same state support during the critical early industrialisation period. The post-1919 growth of Indian industry when some protection was allowed confirms that colonial policy (not Indian inability) was the key constraint." },
  { q:"ASSERTION: The colonial relationship between Britain and India was fundamentally about economic extraction, with political control as the means.\nREASON: India served as a source of raw materials, a market for British manufactured goods, and a source of revenue to pay for British imperial administration — political control made economic extraction possible.", opts:["Both A and R true; R correctly explains the economic logic of colonialism","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"This is the core of economic imperialism theory. Political control (the Raj) was not an end in itself but the means to economic advantage: (1) Tariff policy that opened India to British goods while restricting Indian exports to Britain. (2) 'Home charges' — India paid for its own colonial administration plus British military costs. (3) India's gold reserves drained during the Depression. (4) Indian railways built with Indian revenues primarily to serve British commercial interests. The political apparatus of colonialism existed to serve the economic extraction." },
  { q:"EXTRACT-BASED: 'The Industrial Revolution was as much a social and cultural revolution as a technological one.' Justify with evidence.", opts:["The Industrial Revolution was only technological","Social change came after technology","True — industrialisation transformed: family structure (women and children became wage workers); urban geography (industrial cities replaced rural villages); class structure (bourgeoisie rose, aristocracy declined, working class formed); culture (novels like Dickens addressed industrial life); religion (evangelical Christianity responded to industrial poverty); leisure (music halls, football clubs emerged from urban industrial culture)","Technology had no social effects"], ans:2, exp:"The social-cultural transformation was profound. The nuclear urban family (separated from extended rural family) is an industrial invention. The modern weekend (Saturday half-day, Sunday off) was a response to industrial overwork. Football clubs were founded by factory workers. Trade unionism was a cultural response. The novel as a literary form emerged alongside industrialisation — Dickens, Gaskell writing industrial social criticism. Modern concepts of 'work' and 'leisure' as separate categories are industrial inventions. Technology enabled but culture shaped industrialisation's meaning." },
  { q:"CASE-BASED: Why did some regions of India benefit from colonialism's economic changes while others suffered devastating losses?", opts:["All regions suffered equally","All regions benefited","The impact was geographically and sectorally differentiated: (1) Coastal regions near ports benefited from expanded trade. (2) Raw material producing regions (Punjab for wheat, Gujarat for cotton, Bengal for jute) experienced commodity booms. (3) Manufacturing regions (Bengal weavers, Dhaka muslin, Surat textiles) suffered devastating de-industrialisation. (4) Railway towns grew; traditional craft centres declined. The pattern reveals colonial capitalism's selective development — growth where it served British interests, destruction where it threatened British manufacturing","No differentiation occurred"], ans:2, exp:"Regional differentiation is crucial to understanding colonialism's economic impact. The 'drain theory' of Indian nationalists (Dadabhai Naoroji) focused on aggregate extraction. But the geographic reality was more complex: Punjab's peasants benefited from canal irrigation (built partly for imperial revenue purposes). Gujarat's cotton farmers prospered during American Civil War cotton boom. But Bengal's weavers, Dhaka's muslin craftsmen, and Surat's cloth traders faced systematic destruction. Colonial development was 'combined and uneven'." },
  { q:"ASSERTION: The debate between Dadabhai Naoroji's 'drain theory' and colonial apologetics about India's economic development reveals the fundamentally political nature of economic arguments.\nREASON: Both sides selected evidence to support their political positions — nationalists emphasised extraction, colonialists emphasised railways and infrastructure — revealing that economic history is never purely objective.", opts:["Both A and R true; R reveals the political context of economic debate","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. Dadabhai Naoroji's drain theory (India was being systematically impoverished by colonial extraction) was political — designed to mobilise nationalist sentiment. Colonial apologetics (India benefited from British administration, railways, and legal systems) was also political — designed to justify colonialism. Both contained partial truths. Modern economic history tries to separate evidence from advocacy, but the debate over colonialism's net economic impact on India remains alive and politically charged today — showing R is correct about the political nature of economic arguments." },
  { q:"How does the experience of Indian mill workers in the late 19th century challenge both nationalist and Marxist narratives about industrialisation?", opts:["It confirms both narratives completely","It challenges neither","It challenges the nationalist narrative (which celebrated Indian industry as inherently liberatory) by showing that Indian mill owners exploited workers as harshly as British colonists exploited India; it challenges some Marxist narratives by showing that caste, religion and ethnicity divided the working class in ways that prevented simple class solidarity — showing that social identities other than class shaped industrial experience","The experience of workers is not relevant to these debates"], ans:2, exp:"This is sophisticated historical analysis. Nationalist narrative: Indian capitalism was 'good', colonial capitalism was 'bad'. Reality: Indian mill owners paid poverty wages, used child labour, imposed strict discipline, and opposed trade unions — creating conditions that exposed the limits of nationalist economics. Marxist narrative: class solidarity should unite workers. Reality: Bombay mills were divided by caste (supervisors vs floor workers), religion (Hindu vs Muslim riots in mills), and ethnicity (workers from different provinces). Both grand narratives are challenged by the specific experience of actual workers." },
];


// ═════════════════════════════════════════════════════════
// CH 5 — PRINT CULTURE AND THE MODERN WORLD
// ═════════════════════════════════════════════════════════

const ch5_pyqs = [
  { title:"PYQ 2023", question:"Who invented the printing press? How did it transform European society?", answer:"Johannes Gutenberg invented the printing press with movable type in Mainz, Germany around 1448. Before Gutenberg, books were hand-copied by scribes — enormously time-consuming and expensive, limiting literacy to elites. Gutenberg's press used: (1) Movable metal type that could be rearranged. (2) Oil-based ink. (3) A screw press adapted from winemaking. Transformation of European society: (1) Books became dramatically cheaper — literacy spread. (2) The Bible, previously restricted to Latin, was translated into vernacular languages. (3) Martin Luther's '95 Theses' (1517) was printed and distributed across Europe in weeks — the Reformation would have been impossible without print. (4) Print created a public sphere of debate. (5) Scientific ideas spread rapidly. (6) Print standardised languages, helping create national identities.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2023", question:"How did print culture contribute to the French Revolution?", answer:"Print culture and the French Revolution were deeply connected: (1) Enlightenment ideas spread through printed books and pamphlets — Voltaire, Rousseau, Montesquieu. (2) Pamphlets attacking the King, Queen (Marie Antoinette), and the Church spread rapidly — 'pamphlet wars' preceded the Revolution. (3) Newspapers and journals proliferated — from 50 in 1789 to 300 by 1790. (4) The 'public sphere' — spaces of rational debate created by print — allowed criticism of the monarchy that would have been impossible without print. (5) The Declaration of the Rights of Man (1789) was printed and distributed widely. (6) The idea that 'Print = Dagger' was used by those who feared print's revolutionary power. Historian Jürgen Habermas argued that the print-created public sphere was a precondition for modern democracy.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What was the impact of print culture on women in early modern Europe and India?", answer:"Print culture had complex effects on women: In Europe: (1) More books and literacy materials were available. (2) Women wrote novels and literary works (Jane Austen, George Eliot). (3) But male critics often attacked women writers — advising them to 'stay home'. (4) Print both opened new worlds and provoked conservative reaction. In India: (1) Bengali reformers used print to debate women's issues — Sati, widow remarriage, women's education. (2) Women began reading — social reform literature in vernacular languages reached urban women. (3) Women began writing — Rashsundari Debi (Bengal) taught herself to read and write and wrote her autobiography (1876). (4) Conservative reaction — some religious leaders argued literacy would corrupt women. (5) Nationalist newspapers targeted women readers, bringing them into political consciousness.", year:2022, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What was Gutenberg's printing press and how did it build on existing technologies?", answer:"Gutenberg's press (c. 1448) was a synthesis of existing technologies: (1) Movable type — existed in China (Bi Sheng, 11th century) but in clay; Korea had metal movable type (13th century). Gutenberg made durable, reusable metal type. (2) Screw press — adapted from wine and olive oil pressing. (3) Oil-based ink — adapted from existing painting inks. (4) Paper — invented in China, reached Europe via Arab traders. Significance of synthesis: Gutenberg didn't invent each element but combined them into a system far more efficient than any predecessor. His metal type could be used thousands of times; his press was faster and more uniform than hand-copying. Within 50 years, 20 million books had been printed in Europe — more than all books previously copied by hand.", year:2022, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"How did print culture contribute to the Protestant Reformation?", answer:"Print was essential to the Reformation's success: (1) Martin Luther's 95 Theses (1517) — his criticism of the Catholic Church's selling of indulgences was printed and distributed across Germany within weeks. (2) Bible in vernacular — Luther's German translation of the Bible was printed and became a bestseller. Ordinary people could read the Bible themselves, without priests. (3) Pamphlets — thousands of polemical pamphlets attacking Catholic practices were printed and circulated. (4) Protestantism spread precisely where printing was strongest — in Germany's printing cities. (5) The Catholic Church responded with its own print propaganda — creating a 'war of pamphlets'. Without print, Luther's ideas would have remained a local controversy. Print turned a theological debate into a continent-wide religious revolution.", year:2021, marks:5, difficulty:"hard" },
  { title:"PYQ 2021", question:"What role did printing play in the development of Indian nationalism?", answer:"Print was fundamental to Indian nationalism: (1) Newspapers — vernacular and English newspapers spread nationalist ideas. Bal Gangadhar Tilak's 'Kesari' (Marathi), 'Punjab Kesari' (Punjabi) reached millions. (2) Gandhi used print extensively — Young India, Navajivan, Harijan. (3) Books spread ideas — Bankim Chandra's novels popularised nationalism; Vande Mataram came from a printed novel. (4) Print created a national public sphere allowing shared political debate across India's huge geography. (5) The British Vernacular Press Act (1878) — designed to suppress nationalist newspapers — showed how threatening print was to colonial authority. (6) Pamphlets could spread protest ideas rapidly. (7) Print in multiple vernacular languages helped create regional nationalisms that federated into all-India nationalism.", year:2021, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"How did the colonial government in India try to control print culture? Were these measures effective?", answer:"Colonial measures: (1) Press Censorship Act (1799) — under Governor-General Wellesley — required newspapers to submit to pre-publication censorship. (2) Vernacular Press Act (1878) — specifically targeted Indian-language newspapers with harsh penalties. (3) Sedition laws — used to prosecute editors (Tilak was imprisoned for writing in Kesari). (4) Books offensive to religious or national sentiment could be banned. Effectiveness: (1) Censorship drove some journalism underground — underground nationalist pamphlets proliferated. (2) The Vernacular Press Act was widely resented and eventually repealed (1882). (3) Imprisoning editors (like Tilak) made them national heroes — martyrs who attracted more readers. (4) The colonial government could not stop the flood of print without destroying the commercial and educational infrastructure it needed. Ultimately, the measures were partially effective but insufficient.", year:2020, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"What was the impact of print on the lives of lower castes and untouchables in India?", answer:"Print opened new possibilities for lower castes: (1) Jyotirao Phule — Dalit social reformer used print to spread his ideas about caste oppression. His book 'Gulamgiri' (Slavery, 1873) attacked Brahmin domination. (2) B.R. Ambedkar — used print extensively; his newspapers 'Mooknayak', 'Bahishkrit Bharat', 'Janata' fought for Dalit rights. (3) Tamil-speaking lower castes used the 'non-Brahmin movement's' newspapers. (4) The ability to print and circulate ideas meant that lower-caste voices could reach wider audiences than oral tradition alone allowed. (5) However, access to print was limited by literacy rates — most Dalits were denied education. (6) The printing of anti-caste literature provoked upper-caste backlash.", year:2020, marks:5, difficulty:"hard" },
  { title:"PYQ 2019", question:"How did the novel as a literary form contribute to nationalism in colonial India?", answer:"The novel was crucial to Indian nationalism: (1) Novels were printed in vernacular languages — accessible to middle-class readers who didn't read English. (2) Bankim Chandra Chattopadhyay's novels (Anandamath, Durgesh Nandini) glorified India's past and resistance to foreign rule. Vande Mataram came from Anandamath. (3) Premchand's Hindi novels depicted peasant and lower-caste life, building sympathy for the oppressed. (4) Novels created 'imagined communities' — readers across the country read the same stories, imagined the same 'India'. (5) Women writers' novels brought women's experiences into public consciousness. (6) Historical novels romanticised the pre-colonial past — Maratha glory, Mughal era — creating a narrative of national decline under colonialism that needed to be reversed.", year:2019, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"What was the significance of the printing press for scientific development in early modern Europe?", answer:"Print transformed scientific development: (1) Before print, scientific manuscripts were copied by hand — errors accumulated in each copying, so different scholars had different versions of the same text. Print created standardised, identical copies. (2) Scientists could share findings simultaneously across Europe. (3) Printed books created a permanent, accessible scientific record — scholars built on predecessors' work more easily. (4) Scientific debate moved into print — journals, pamphlets, books. (5) The 'scientific revolution' of the 16th-17th centuries (Copernicus, Galileo, Newton) depended on print to spread ideas. Without print, the Scientific Revolution would have been slower and geographically confined. (6) Print also spread dangerous ideas — Copernicus's heliocentric theory, Galileo's support for it, challenged the Church.", year:2019, marks:3, difficulty:"medium" },
  { title:"PYQ 2023", question:"What is the 'print revolution' and why did it cause fear and anxiety among religious authorities?", answer:"The print revolution (from 1448) was the mass production of books using Gutenberg's press. Before print: books were rare, expensive, controlled by the Church and universities. The Church decided what was written and circulated — maintaining ideological monopoly. Fear of religious authorities: (1) People could now read the Bible themselves without priestly interpretation. (2) Heretical ideas could spread rapidly in print before the Church could respond. (3) Protestant ideas spread through Germany in months — previously impossible. (4) Print created a space outside Church control for debate. (5) The 'Index of Prohibited Books' (1564) — the Church compiled a list of books Catholics were forbidden to read. (6) Writers who challenged Church doctrine were executed — yet their books spread. The Church correctly identified print as threatening its interpretive monopoly over Christian life.", year:2023, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"How did the reading public change with the spread of print culture in Europe?", answer:"The reading public expanded dramatically: (1) Previously: literacy was limited to clergy, aristocrats and some merchants. Books were hand-copied, expensive, in Latin. (2) Print made books affordable: by the 16th century, printed books cost a fraction of hand-copied ones. (3) Vernacular translations — printing in French, German, English rather than Latin — opened books to those without classical education. (4) Literacy spread: schools, reading groups, coffeehouses (where people read newspapers aloud for illiterates). (5) New genres for new readers: romance novels, almanacs, practical manuals, political pamphlets — not just religious texts. (6) Women readers increased: novels were associated with women readers. (7) By 19th century: cheap print (penny press, serialised novels) reached working classes. The reading public went from a tiny elite to (eventually) the entire literate adult population.", year:2022, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"What is the significance of 'reading in silence' as a practice developed in relation to print culture?", answer:"The shift from oral/communal to silent individual reading was a profound cultural change: (1) Medieval reading was almost always aloud — even scholars reading alone read aloud to themselves. (2) Print created private reading spaces — a person could read silently, alone, without sharing the experience. (3) Silent reading enabled intimate, individual engagement with text — ideas could be processed privately before being shared or acted on. (4) It created the possibility of 'private thought' in relation to ideas — dangerous thoughts could be read and considered without community knowledge. (5) Silent reading was associated with women's novel reading — a private, interior experience. (6) It contributed to the development of the modern individual — someone with a private inner life. Print and silent reading together helped create the modern concept of the individual with private beliefs.", year:2021, marks:3, difficulty:"medium" },
  { title:"PYQ 2020", question:"How did print culture change the relationship between rulers and the governed?", answer:"Print fundamentally changed political power relationships: (1) Rulers could no longer control information as completely — printed pamphlets circulated criticisms they couldn't suppress. (2) Public opinion became a political force — rulers had to consider what 'the people' thought, as expressed in print. (3) Print created accountability — rulers' actions were commented on, criticised and recorded. (4) Censorship became a major political issue — attempts to restrict print created the first press freedom debates. (5) Revolutions (American, French) were accompanied by floods of political pamphlets. (6) Governments began using print for propaganda — legitimising their own power. (7) The distinction between 'state' and 'public sphere' emerged partly through print — a space outside government control where citizens debated.", year:2020, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"What were 'chapbooks' and 'ballad sheets' and what was their significance?", answer:"Chapbooks and ballad sheets were cheap popular print: (1) Chapbooks — small, cheap booklets sold by itinerant sellers ('chapmen'). Contained popular stories, religious texts, almanacs, jokes. (2) Ballad sheets — single printed sheets with poems or songs about current events, scandals, religious topics. Could be bought for a penny. Significance: (1) They brought print to people who couldn't afford expensive books — the poor, illiterate (who had them read aloud), rural populations. (2) They created a popular print culture alongside elite print culture. (3) They spread news, rumour, and political commentary outside official channels. (4) They helped standardise popular cultural knowledge across regions. (5) They are important historical sources for understanding popular beliefs and concerns. In India, similar cheap print (almanacs, religious pamphlets) played comparable roles in spreading ideas to non-elite readers.", year:2019, marks:3, difficulty:"medium" },
];

const ch5_easyMCQ = [
  { q:"Who invented the printing press with movable type?", opts:["Marco Polo","Johannes Gutenberg","William Caxton","Martin Luther"], ans:1, exp:"Johannes Gutenberg invented the printing press with movable metal type in Mainz, Germany around 1448. This allowed mass production of books at dramatically lower cost, transforming European culture and eventually world history." },
  { q:"Where was the printing press first invented before Europe?", opts:["India","Africa","China","Egypt"], ans:2, exp:"The printing press was first invented in China. Bi Sheng invented clay movable type around 1040 CE. Korea developed metal movable type in the 13th century. Japan also had early printing. However, these did not spread to Europe, where Gutenberg independently invented his metal movable type system around 1448." },
  { q:"Martin Luther's '95 Theses' criticised:", opts:["The Roman Emperor","The selling of indulgences by the Catholic Church","The printing press","The Ottoman Empire"], ans:1, exp:"Luther's 95 Theses (1517) attacked the Catholic Church's practice of selling 'indulgences' — essentially payments to reduce time in purgatory. They were printed and distributed across Germany in weeks, sparking the Protestant Reformation. Without print, Luther's protest would not have become a continent-wide revolution." },
  { q:"The Vernacular Press Act (1878) in India was designed to:", opts:["Promote vernacular literature","Suppress Indian-language newspapers that criticised British rule","Translate English books into Indian languages","Train Indian printers"], ans:1, exp:"The Vernacular Press Act gave the colonial government power to confiscate printing presses and materials of newspapers publishing 'seditious' content in Indian languages. It was specifically targeted at nationalist journalism. It was widely resented and repealed in 1882 after strong protests." },
  { q:"Rashsundari Debi is significant in the history of Indian print culture because:", opts:["She was the first woman printer","She wrote the first autobiography in Bengali — teaching herself to read and write in secret around 1876","She ran a major publishing house","She translated the Bible into Bengali"], ans:1, exp:"Rashsundari Debi's autobiography 'Amar Jiban' (My Life, 1876) is the first known autobiography written by a woman in Bengali. She taught herself to read by stealing pages from her son's books and tracing letters with sticks in the kitchen floor. Her literacy was an act of personal rebellion against norms that denied women education." },
  { q:"The first book to be printed in India using a printing press was:", opts:["The Bhagavad Gita","A catechism in Tamil by Portuguese missionaries in 1577","The Ramayana","The Quran"], ans:1, exp:"The first printed book in India was a catechism (a Catholic religious text) printed in Tamil by Portuguese missionaries in Goa in 1577. The printing press came to India as a tool of Christian evangelism before becoming a vehicle for Indian cultural and nationalist expression." },
  { q:"Who wrote the novel 'Anandamath' from which Vande Mataram comes?", opts:["Rabindranath Tagore","Premchand","Bankim Chandra Chattopadhyay","Kazi Nazrul Islam"], ans:2, exp:"Bankim Chandra Chattopadhyay wrote Anandamath (1882), a Bengali novel about a Sanyasi rebellion against British rule. The song 'Vande Mataram' — later India's national song — comes from this novel. It shows how the novel as a printed form became a vehicle for nationalist ideology." },
  { q:"The 'Index of Prohibited Books' was created by:", opts:["The British government","The Roman Catholic Church to list books Catholics were forbidden to read","The French Revolution","The German printing guilds"], ans:1, exp:"The Index Librorum Prohibitorum (Index of Prohibited Books) was created by the Catholic Church in 1564 in response to the print revolution. It listed books whose ideas were considered heretical or dangerous. Authors whose works appeared on the Index were sometimes executed, yet print made complete censorship impossible." },
  { q:"What is 'yellow journalism'?", opts:["Journalism using yellow ink","Sensationalist journalism using exaggerated stories to attract readers — common in 19th century mass circulation newspapers","Journalism in Asian countries","Official government journalism"], ans:1, exp:"'Yellow journalism' refers to sensationalist reporting that exaggerates, distorts or fabricates stories for dramatic effect. The term originates from the rivalry between New York newspapers (Pulitzer's World and Hearst's Journal) in the 1890s. It represents the dark side of mass circulation print — the commercial pressure to entertain rather than inform." },
  { q:"The first printing press in Calcutta was established by:", opts:["British traders","James Augustus Hickey, who also published Bengal Gazette (1780) — India's first newspaper","Christian missionaries","Rabindranath Tagore's family"], ans:1, exp:"James Augustus Hickey established the first printing press in Calcutta and published Bengal Gazette (also known as Hickey's Gazette) from 1780 — the first newspaper in India. It was politically outspoken and was eventually suppressed by Governor-General Warren Hastings." },
  { q:"What is a 'pamphlet'?", opts:["A large newspaper","A small, unbound booklet discussing a single topic or controversy — cheap to print and widely circulated in early print culture","A royal proclamation","A religious text"], ans:1, exp:"Pamphlets were small, cheap, quickly-produced booklets (a few pages to perhaps 50 pages) covering a single political, religious or social topic. They were cheap enough to be distributed widely. Luther, Voltaire, Thomas Paine (Common Sense, 1776), and Indian nationalists all used pamphlets to spread ideas. They were the social media of early print culture." },
  { q:"In colonial India, newspapers in English served primarily:", opts:["Ordinary Indians who spoke English","The educated Indian elite and British officials — creating a small but influential English-language public sphere","Children learning English","Religious communities only"], ans:1, exp:"English-language newspapers in colonial India (The Hindu, Amrita Bazar Patrika, The Statesman) served the educated English-speaking elite — a small percentage of the population but disproportionately powerful in nationalist politics. They could communicate across India's many languages, creating an all-India nationalist conversation." },
  { q:"The practice of reading aloud in pre-print and early print culture served what social function?", opts:["It helped the deaf","Oral reading allowed texts to reach the illiterate — servants, peasants, women without formal education could access ideas through listeners when they could not read themselves","It was required by law","Books could only be understood when read aloud"], ans:1, exp:"In the early print era, most people were illiterate. Reading aloud in coffeehouses, homes and public spaces made print culture accessible beyond the literate minority. A newspaper read aloud in a coffeehouse reached dozens who couldn't read. This oral transmission of print ideas was crucial to the French Revolution, Indian nationalism, and most mass political movements." },
  { q:"Bal Gangadhar Tilak used which newspaper as a vehicle for nationalist propaganda?", opts:["The Hindu","Amrita Bazar Patrika","Kesari","Young India"], ans:2, exp:"Bal Gangadhar Tilak used Kesari (Lion) — a Marathi language newspaper he founded in 1881 — as a major vehicle for aggressive nationalist journalism. He was imprisoned twice for sedition for articles in Kesari. Young India was Gandhi's newspaper; The Hindu was from Madras." },
  { q:"What is the significance of the cheapening of print in 19th century Europe?", opts:["Cheaper print meant lower quality","Penny press, serialised novels, cheap magazines made print accessible to working classes for the first time — massively expanding the reading public and creating modern mass literacy","Cheap print was only for children","Cheap print replaced expensive print completely"], ans:1, exp:"The cheapening of print in the 19th century (through steam-powered presses, cheaper paper, mass distribution) created mass literacy and mass media. Penny newspapers (one penny per copy) reached working-class readers. Serialised novels in weekly magazines (Dickens published serially) made fiction affordable. This democratisation of reading was a social revolution." },
];

const ch5_mediumMCQ = [
  { q:"Why did the Catholic Church find print threatening and how did it respond?", opts:["The Church supported print fully","Print was neutral — the Church had no concerns","Print threatened the Church's interpretive monopoly over Christian doctrine — anyone could now read the Bible in vernacular and form their own interpretations. The Church responded with the Index of Prohibited Books, censorship, and persecution of heretical writers","Print helped the Church spread its ideas"], ans:2, exp:"The Church's power rested partly on being the sole interpreter of Christian doctrine. When ordinary people could read the Bible themselves (in Luther's German translation, printed in hundreds of thousands of copies), they could reach their own conclusions — challenging priestly authority. The Inquisition burned books; the Index listed forbidden texts; Galileo was forced to recant. But the Church could not suppress print without destroying the educational system it needed." },
  { q:"How did the printing press contribute to the standardisation of European languages?", opts:["The press had no effect on language","Printers and publishers deliberately created standard forms of languages that everyone could read — eliminating regional variations — creating unified linguistic communities that became the basis for national identities","Printing increased linguistic diversity","Each region maintained its own language"], ans:1, exp:"Before print, every region had its own dialect — a Bavarian German and a Prussian German could barely understand each other. Printers needed to choose which dialect to publish in to maximise sales. They chose dialects most widely understood (or mixed them). Publishers' choices gradually standardised 'German', 'French', 'English'. Luther's Bible standardised written German. The English King James Bible (1611) standardised English. Print-language standardisation preceded and enabled national identity." },
  { q:"What is the connection between print culture and the development of public opinion?", opts:["Print and public opinion are unrelated","Print created spaces for debate — coffeehouses, reading clubs, newspapers — where 'public opinion' formed outside government control, becoming a political force that rulers increasingly had to consider","Public opinion existed before print","Print suppressed public opinion"], ans:1, exp:"Philosopher Jürgen Habermas argued that 'the public sphere' — a space of rational debate between citizens — was created by print culture. Coffeehouses (17th-18th century) were places where people gathered to read newspapers and debate political issues. This created 'public opinion' as a concept and force. Rulers who had previously governed without consulting anyone now found themselves measured against public opinion expressed through print. The French Revolution was partly a product of this print-created public sphere." },
  { q:"Why was the Vernacular Press Act (1878) resented and eventually repealed?", opts:["It was too expensive to enforce","Indians welcomed it","It was seen as discriminatory — English newspapers could criticise the government freely while Indian-language papers faced suppression. It also created martyrs of imprisoned editors. It was repealed (1882) by a more liberal Viceroy (Ripon) who recognised its counter-productive effects","It achieved its aims completely"], ans:2, exp:"The Vernacular Press Act's hypocrisy was obvious: English newspapers (read mainly by the British and educated Indians) could criticise the government relatively freely, while Indian-language newspapers (read by the expanding literate Indian public) faced draconian penalties. The Amrita Bazar Patrika famously switched from Bengali to English overnight to escape its provisions. Imprisoning editors (Tilak etc.) made them heroes. Lord Ripon repealed it, recognising it was creating more resentment than security." },
  { q:"How did the novel as a form contribute to the creation of 'imagined communities' in colonial India?", opts:["Novels only entertained — no political effect","Novels were not read widely in India","Novels printed in vernacular languages allowed millions to imagine themselves as part of a shared community with the same history, heroes and cultural heritage — creating the emotional bonds of national identity across vast distances","Only English novels mattered"], ans:2, exp:"Benedict Anderson's concept of 'imagined community' applies perfectly here. A Bengali reader of Bankim Chandra's novels shared with thousands of other Bengali readers the same heroes, the same images of a glorious pre-colonial past, the same anger at colonial oppression. They would never meet each other, but they were bound by a shared imaginative community created by print. This emotional nationalism was as important as political nationalism — it created the feeling that made political nationalism possible." },
  { q:"What role did print play in the reform movements against Sati and for widow remarriage in 19th century India?", opts:["Print had no role in social reform","Social reform movements used print strategically — newspapers, pamphlets, books debated and publicised the cases of Sati and widow suffering — building public opinion for legislative reform. Raja Ram Mohan Roy used print extensively; Ishwar Chandra Vidyasagar campaigned for widow remarriage through print","Print supported Sati","The British used print to suppress reform"], ans:1, exp:"Print was the instrument of social reform. Raja Ram Mohan Roy published pamphlets attacking Sati (widow burning) in both English and Bengali — building both British and Indian support for abolition (1829). Vidyasagar wrote extensively on widow remarriage, mobilising opinion. Print created a 'public' that could be persuaded and whose opinion mattered to colonial officials making policy. Without print, these reforms would have remained private petitions." },
  { q:"Why did colonial authorities sometimes find that suppressing print was counterproductive?", opts:["Suppression always worked","The colonial government never tried to suppress print","Suppressed publications became more desirable; imprisoned editors became martyrs and heroes; censorship attempts provoked outrage that created more readers. The Vernacular Press Act, Sedition laws against Tilak — all backfired by martyring their victims and radicalising wider opinion","Suppression only affected poor people"], ans:2, exp:"This is the 'Streisand effect' in colonial history. Tilak's imprisonments for Kesari made him 'Bal Gangadhar Tilak, Lokamanya (respected by the people)' — a national hero. Banned books were hunted out and read more eagerly. The colonial government faced an impossible choice: suppress and create martyrs, or allow and be criticised. Print created a dilemma that colonial censorship could not resolve." },
  { q:"How did the printing press contribute to the development of modern science?", opts:["Science developed despite the printing press","Printing had no effect on science","Print allowed scientists to communicate simultaneously across Europe, to build precisely on each other's standardised texts (no copying errors), to debate findings publicly, and to create a cumulative scientific tradition — essential to the Scientific Revolution","Science developed before print"], ans:2, exp:"The Scientific Revolution (Copernicus 1543, Galileo 1610, Newton 1687) was inseparable from print. Copernicus's heliocentric theory was published as a printed book — it could not have been suppressed as a manuscript could. Newton's Principia Mathematica was published simultaneously for all European scientists. Scientific journals (from 1660s) created regular, cumulative communication. Without print standardisation (no copying errors) and distribution, the Scientific Revolution's rapid development would not have been possible." },
  { q:"What is the difference between censorship and self-censorship in the context of print culture?", opts:["They are the same thing","Censorship is government suppression; self-censorship is writers/editors anticipating government reaction and moderating their own content — often more effective than direct censorship because it operates invisibly and continuously","Self-censorship doesn't exist","Only censorship matters for print history"], ans:1, exp:"Self-censorship is the internalization of censorship norms. When journalists know that certain topics will result in imprisonment or newspaper closure, they avoid those topics without being explicitly told to. This is often more effective than direct censorship — it silences ideas before they reach print without requiring active government intervention. Colonial India's press operated under constant awareness of sedition laws, leading editors to carefully calibrate how far to push nationalist content." },
  { q:"What is the significance of the 'reading room' as a social institution in the history of print culture in India?", opts:["Reading rooms were libraries only","They were places of private reading","Reading rooms (particularly in Bengal, Kerala and Maharashtra) were public spaces where newspapers and books were available and read aloud — making print accessible to the non-literate while creating spaces for political discussion, debate and the formation of nationalist consciousness among working and lower-middle classes","Reading rooms were only for the educated elite"], ans:2, exp:"Reading rooms were crucial nodes in the spread of Indian nationalism. In coastal Kerala, for instance, reading rooms (vayanasal) became centres of social reform and nationalist activity — particularly for lower castes. They democratised print by providing access to those who couldn't afford to buy newspapers and literacy by providing spaces where literate members could read to others. They were simultaneously cultural, educational and political institutions." },
  { q:"How did the development of Tamil print culture connect to lower-caste social movements?", opts:["Tamil print was only for Brahmins","Print had no connection to caste in Tamil Nadu","Tamil vernacular print enabled non-Brahmin and Dalit writers, thinkers and activists to articulate their experiences and demands — the 'non-Brahmin movement' used newspapers and pamphlets to challenge Brahmin intellectual and social dominance","Tamil print only concerned literary matters"], ans:2, exp:"Tamil print culture is particularly fascinating for caste politics. Lower-caste Tamil leaders used newspapers (Kudi Arasu by Periyar E.V. Ramasamy) to attack caste discrimination and promote a rationalist, anti-religious social reform agenda. This 'Dravidian' movement used print to challenge not just British colonialism but also upper-caste Hindu dominance — creating a distinctive regional political culture that continues to shape Tamil Nadu politics." },
  { q:"What is the relationship between oral culture and print culture in colonial India?", opts:["Print replaced oral culture completely","They existed in entirely separate spheres","Print and oral culture were deeply interpenetrated — print texts were read aloud in public spaces, oral performances used printed scripts, newspapers were read to illiterate audiences, songs from printed novels became oral traditions. The boundary between 'oral' and 'print' cultures was permeable and dynamic","Oral culture was more important than print"], ans:2, exp:"India's colonial print culture was hybrid from the start. Songs from Bankim Chandra's novels entered the oral tradition and were sung at nationalist meetings. Gandhi's speeches were reported in newspapers which were then read aloud at village gatherings. Ram Lila performers used printed scripts. Jatras (folk theatre) began using printed texts. This interpenetration means we cannot study Indian print culture in isolation from the oral culture it mixed with." },
  { q:"Why is the history of print in colonial India inseparable from the history of language politics?", opts:["Language and print are unrelated","Print only mattered in English","Print required choosing a language — and in multilingual India, this was always a political choice. Hindi vs Urdu (sharing spoken language but using different scripts), Sanskrit vs vernacular, English vs Indian languages — each print choice reflected and reinforced social hierarchies, communal identities, and nationalist claims","Language politics began after print"], ans:2, exp:"The 'Hindi-Urdu controversy' is the perfect example: Hindi (Devanagari script) and Urdu (Perso-Arabic script) were mutually intelligible spoken languages but printed in different scripts — creating separate literary cultures and political identities. The decision to print in Hindi with Sanskrit vocabulary versus Urdu with Persian vocabulary was a communal-political choice, not just a linguistic one. This language-print nexus contributed to communal polarisation in north India with lasting consequences." },
  { q:"What does the spread of print culture reveal about the relationship between literacy and social power?", opts:["Literacy is politically neutral","Print made everyone equal","Throughout history, those who controlled reading and writing controlled information and hence power. Print democratised access to knowledge, threatening existing power structures (clergy, aristocracy, upper castes). Those in power tried to restrict literacy (women's education, Dalit education), while reformers promoted literacy as empowerment. Print culture is therefore inseparable from struggles over social power","Literacy only matters economically"], ans:2, exp:"This is the political economy of literacy. Medieval Europe: the Church kept the Bible in Latin (which ordinary people couldn't read), maintaining interpretive monopoly. Colonial India: British higher education gave English-speakers structural advantages. Upper castes: traditionally controlled Sanskrit learning, keeping lower castes illiterate and dependent. Each case shows that literacy is not neutral — controlling who can read (and in what language) is a form of power. Print progressively democratised this power, which is why powerful groups have always tried to restrict it." },
  { q:"How did the development of the periodical press (regular newspapers and journals) change political life differently from books?", opts:["Newspapers had no different effect from books","Newspapers were less important than books","Periodicals — daily and weekly newspapers — created political time differently from books: they produced immediate commentary on current events, created public opinion in real time, connected citizens to politics as an ongoing process rather than historical record, and made government actions immediately accountable. Books preserved knowledge; newspapers created political life as it happened","Books were more political than newspapers"], ans:2, exp:"The periodical press fundamentally changed political temporality. A book about the French Revolution published in 1800 was historical. A newspaper published during the Revolution created political life in real time. This immediacy made newspapers uniquely powerful: they could mobilise opinion within days, connect dispersed readers to a shared political moment, and create 'public opinion' as a current force rather than a historical judgment. The slogan 'the press is the fourth estate' reflects this — newspapers as an ongoing force checking executive power." },
];

const ch5_hardMCQ = [
  { q:"ASSERTION: The printing press was the most important cause of the Protestant Reformation.\nREASON: Luther's ideas spread across Europe within weeks through print — something impossible to achieve without the press.", opts:["Both A and R true; R explains A","Both true but R doesn't explain why print was the most important cause","A overstates; printing was necessary but not sufficient — Luther's ideas had to resonate with existing grievances","A false, R true"], ans:2, exp:"The nuanced answer: print was necessary but not sufficient. Luther's ideas resonated because of pre-existing grievances: clerical corruption, Church wealth, peasant poverty, rising nationalism in Germany against 'Roman' exploitation. Without print, Luther would have been a local controversy. Without the underlying social tensions, print alone could not have created a Reformation. Both print technology AND social conditions were required — making 'most important cause' an overstatement for print alone." },
  { q:"CASE-BASED: A historian argues that 'the history of censorship is the history of power'. How does the evidence of colonial Indian press history support this?", opts:["Censorship had no connection to power","Power only used censorship occasionally","The colonial government's censorship of Indian-language press (Vernacular Press Act, sedition laws) while allowing English press more freedom reveals how power operated through language and literacy — controlling which ideas reached the masses while allowing elite debate. The censorship history maps precisely onto the power structure of colonialism","All censorship was equally applied"], ans:2, exp:"The differential censorship of English vs vernacular press perfectly reveals the power dynamics. The English-reading elite (both British and Indian) were allowed more debate — they were not the threat to colonial stability. The vernacular press, reaching millions of ordinary Indians, was the real political threat. By controlling what ordinary Indians could read in their own languages, colonial power tried to maintain the political passivity of the majority. The Vernacular Press Act is therefore a document of colonial power operating through language." },
  { q:"EXTRACT-BASED: 'Print created not just literacy but a new kind of selfhood.' Explain this philosophical claim.", opts:["Print only affected reading skills","Print changed nothing about identity","True — silent individual reading created a private inner space where ideas could be processed without community surveillance; print enabled people to encounter ideas never encountered in their community; vernacular print created language-based identities (national, religious, caste) larger than the village; autobiographies (like Rashsundari Debi's) created the genre of the individual life as meaningful narrative — all aspects of a new, modern, individual selfhood","Selfhood existed before print"], ans:2, exp:"This is the philosophical depth of print culture's impact. Before print: identity was primarily communal — one was a member of a village, caste, religion, family. Silent reading created a private self that encountered ideas privately. Novels gave people access to imagined inner lives of others, developing empathy and individuality. Autobiographies said: one individual life is worth recording. Print in one's native language said: your language-community has a shared history and identity worth knowing. All these are aspects of the modern individual self — constructed partly through print." },
  { q:"ASSERTION: Jyotirao Phule and B.R. Ambedkar used print as an instrument of liberation for Dalit communities.\nREASON: By articulating Dalit experiences and demanding rights through newspapers and books, they created a counter-discourse challenging Brahminic cultural dominance — showing print as a weapon of the oppressed.", opts:["Both A and R true; R explains how print served as liberation","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. The subversive use of print by oppressed groups is a recurring pattern: Phule's 'Gulamgiri' attacked caste through the very medium (print) that upper castes had traditionally monopolised. Ambedkar's newspapers gave Dalits their own media voice. Print allowed them to bypass the social authority of Brahmin priests and scholars — reaching Dalit readers directly. This use of print as counter-power, challenging dominant narratives, is one of print culture's most important stories." },
  { q:"CASE-BASED: Compare the role of print in the French Revolution and the Indian independence movement. What are the key similarities and differences?", opts:["They were completely different","Print played no role in either","Similarities: both used print to spread revolutionary ideas; both created publics outside government control; both faced censorship; pamphlets/newspapers were primary vehicles. Differences: French revolution was fast/violent; Indian was slow/non-violent; French print challenged an absolute monarch; Indian print challenged colonial rule while also challenging internal social hierarchy (caste, gender); Indian print operated in multiple languages creating complex multi-lingual nationalism","Only the French used print for revolution"], ans:2, exp:"The comparison reveals both universals and specifics of print in revolution. Universal: print creates publics that can challenge authority. Specific differences: France had one language; India had hundreds — creating a more complex nationalist print culture. French pamphlets attacked one king; Indian newspapers had to simultaneously challenge British colonialism AND internal caste/gender hierarchies (often contradictory). French revolution moved quickly through print; Indian took decades. These differences shaped how print nationalism functioned in each context." },
  { q:"EXTRACT: 'The history of print is the history of knowledge becoming a commodity.' Evaluate.", opts:["Knowledge was always a commodity","Knowledge was never a commodity","True — before print, knowledge was embedded in social relationships (teacher-student, priest-layperson). Print turned knowledge into an object that could be bought, sold, owned, copied, and distributed — transforming knowledge from a social good into a commodity. Publishing industries emerged to profit from this. But also: commodified knowledge reached more people, democratising what had been restricted. The commodity form of knowledge both widened access and created new inequalities","Knowledge has no relationship to economics"], ans:2, exp:"This is a profound insight about print's political economy. Manuscript knowledge circulated through social networks of patrons, scholars and institutions. Print created the book as a commodity: publishers invested capital, priced books to recover costs, competed for markets. This commodification had paradoxical effects: it expanded access (cheaper than manuscripts) while creating new barriers (literacy, cost). The tension between knowledge as a public good and knowledge as private property — central to contemporary debates about copyright and open access — originates in the print revolution." },
  { q:"ASSERTION: The development of print culture in India was fundamentally shaped by the colonial encounter.\nREASON: Printing technology came with colonialism (missionaries, Company), vernacular print developed partly in response to it, and the content of Indian print was inseparable from the colonial relationship.", opts:["Both A and R true; R explains why the colonial encounter was formative","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. Indian print culture was not indigenous (though Indian manuscripts had long traditions). The press arrived with Portuguese missionaries, developed under British colonial administration, and the content of early Indian print was largely shaped by the encounter with colonialism: social reform debates were partly responses to Christian missionary criticism of Hindu practices; nationalist newspapers were responses to colonial rule; vernacular literary renaissances were partly assertions of cultural identity against colonial denigration. The colonial encounter was the matrix within which Indian print culture developed." },
  { q:"CASE-BASED: Why did the relationship between print culture and religious identity in India produce both reform and conflict?", opts:["Print was only used for religious purposes","Print and religion were always compatible","Print had paradoxical effects on religion: it spread reformist ideas challenging superstition and caste (Roy, Phule, Ambedkar); it also allowed printing of religious texts that standardised and sometimes hardened religious identities; communal newspapers promoted religious communities as political identities; fatwas and religious controversies spread through print, mobilising communities against each other. Print simultaneously reformed and radicalised religious life.","Print had no effect on religion"], ans:2, exp:"This captures print's paradox in the religious sphere. The same technology that allowed Raja Ram Mohan Roy to argue rationally against Sati also allowed printers to mass-produce inflammatory communal content. The printing of Ramcharitmanas in cheap editions spread Bhakti devotion across north India. The printing of cow protection pamphlets mobilised Hindu sentiment against Muslims. Print democratised religious engagement while also enabling religious mobilisation for political ends. Reform and conflict were both products of the same print revolution." },
  { q:"ASSERTION: Modern democracy requires a free press not just for information but as a structural component of democratic governance.\nREASON: A free press creates accountability by publishing information about government actions, enables citizens to form informed opinions, provides a forum for political debate, and checks government power — functions that make democracy operational rather than merely formal.", opts:["Both A and R true; R explains the structural functions of press freedom","Both true but unrelated","A true, R partially true","A false, R true"], ans:0, exp:"Both correct and connected. Democracy's formal elements (elections, rights) require functional elements to work: citizens need information to vote meaningfully (press informs); politicians need to be held accountable between elections (press scrutinises); citizens need spaces for debate (press creates public sphere). A democracy with controlled press is hollow — people vote but cannot access accurate information. This is why press freedom is considered a fourth estate and why authoritarian governments attack free media first — they correctly identify it as essential to functioning democracy." },
  { q:"EXTRACT-BASED: 'Print culture created new possibilities for oppression as well as liberation.' How does this apply to the history of print in colonial and modern India?", opts:["Print was always liberatory","Print was always oppressive","True — colonial oppression used print (colonial textbooks, census categories, English-language legal system); caste oppression was reinforced by printing of sacred texts upholding varna system; communal violence was inflamed by sensationalist newspapers; state propaganda used print. Simultaneously: Dalit movements used print for liberation; women used print to enter public sphere; nationalists used print to build independence movement. The same technology served opposite ends depending on who controlled it and for what purpose.","Print is neutral technology"], ans:2, exp:"This is the fundamental insight about technology: it is not inherently liberatory or oppressive — it amplifies the intentions of its users. Colonial administrators used print to classify and control Indian populations (census, land records). Upper castes used printed sacred texts to justify social hierarchy. Communal newspapers inflamed Hindu-Muslim violence. But Ambedkar used print to fight caste; Gandhi used print to build non-violent resistance; women used novels to imagine different lives. Technology creates possibilities; social forces determine whether those possibilities are used for liberation or oppression." },
  { q:"CASE-BASED: A media scholar argues that 'the internet is the new printing press'. What are the strongest parallels and disanalogies?", opts:["There is no parallel","They are completely identical","Strong parallels: both democratised information access; both threatened established authority (Church then, governments/corporations now); both spread ideas across previously insurmountable barriers; both enabled new publics outside existing power structures. Key differences: internet is interactive (print was one-way); information spreads in seconds not weeks; internet enables both hyperconnection and filter bubbles; verification is harder online. The printing press analogy illuminates internet's transformative potential while the differences warn against assuming identical consequences","The comparison is meaningless"], ans:2, exp:"This is a genuinely important question for understanding both media revolutions. The parallels are structural: both technologies democratised information, threatened monopoly knowledge-holders, and enabled revolutionary political movements. But the disanalogies matter: the printing press enabled slow, deliberate dissemination of carefully crafted arguments (pamphlets, books). The internet enables instant, viral, unverified information. Print required some infrastructure (printing press, distribution) that slowed spread and required minimal organisation. The internet's speed, interactivity, and scale of personalization creates different dynamics — including the 'post-truth' environment that print's relative slowness may have partly prevented." },
  { q:"ASSERTION: The development of vernacular print cultures in India contributed to both nationalism and communalism simultaneously.\nREASON: Printing in Bengali, Hindi, Urdu, Tamil created language-based identities that could unite people across caste and class but also harden religious-linguistic boundaries between communities.", opts:["Both A and R true; R explains the paradox","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct and connected. Bengali print created Bengali nationalist identity (useful for anti-colonial nationalism) but also Bengali Hindu vs Bengali Muslim tensions (Bengali vs Urdu-Muslim identities). Hindi print in Devanagari script was associated with Hindu nationalism; Urdu print in Perso-Arabic script with Muslim identity. Tamil print created Dravidian identity partly against north Indian-Hindi nationalism. These print-language communities were building blocks of nationalism but also fault lines of communal tension. The nation AND its internal contradictions were both products of print culture." },
  { q:"CASE-BASED: How does the contrast between 'print capitalism' (Benedict Anderson's term) and print as a tool of social movements challenge simple narratives about print as liberation?", opts:["Print capitalism and social movements are the same","Print capitalism is always bad","Anderson's 'print capitalism' describes how publishers, seeking profit, standardised languages and created mass reading publics as a commercial enterprise — nationalism was partly a product of commercial print culture, not just political idealism. Social movements (Dalit, feminist, labour) then used this infrastructure for political ends. The paradox: capitalism created the print infrastructure; social movements turned it against capitalist social relations. Print liberation required the commercial development that created the inequality social movements challenged","Print capitalism has nothing to do with nationalism"], ans:2, exp:"This is a sophisticated insight about the relationship between capitalism and social movements. Anderson's key point: publishers chose to print in vernacular languages that maximised readers (commercial logic) → standardised languages → created linguistic communities → became bases for nationalism. Capitalism created nations unintentionally through the profit motive. But the same print infrastructure created by capitalist publishers was then used by anti-capitalist social movements. The liberation and the exploitation are inseparable aspects of the same print capitalism." },
];




// ═════════════════════════════════════════════════════════
// MAIN SEED FUNCTION
// ═════════════════════════════════════════════════════════

const seedHistory = async () => {
  try {
    await mongoose.connect(process.env.MONGO_URI);
    console.log("✅ Connected to MongoDB");

    const slugs = [
      "rise-of-nationalism-in-europe",
      "nationalism-in-india",
      "making-of-a-global-world",
      "age-of-industrialisation",
      "print-culture-and-the-modern-world",
    ];

    const chapters = await Chapter.find({ slug: { $in: slugs } });
    if (!chapters.length) {
      console.error("❌ No history chapters found. Run main seed.js first.");
      process.exit(1);
    }

    const map = {};
    chapters.forEach((c) => { map[c.slug] = c; });

    const chapterIds = chapters.map((c) => c._id);
    await Resource.deleteMany({ chapterId: { $in: chapterIds } });
    console.log(`🗑️  Cleared old resources for ${chapters.length} history chapters`);

    // Seed each chapter
    const chaptersData = [
      { slug: "rise-of-nationalism-in-europe",       pyqs: ch1_pyqs, easyMCQ: ch1_easyMCQ, mediumMCQ: ch1_mediumMCQ, hardMCQ: ch1_hardMCQ },
      { slug: "nationalism-in-india",                pyqs: ch2_pyqs, easyMCQ: ch2_easyMCQ, mediumMCQ: ch2_mediumMCQ, hardMCQ: ch2_hardMCQ },
      { slug: "making-of-a-global-world",            pyqs: ch3_pyqs, easyMCQ: ch3_easyMCQ, mediumMCQ: ch3_mediumMCQ, hardMCQ: ch3_hardMCQ },
      { slug: "age-of-industrialisation",            pyqs: ch4_pyqs, easyMCQ: ch4_easyMCQ, mediumMCQ: ch4_mediumMCQ, hardMCQ: ch4_hardMCQ },
      { slug: "print-culture-and-the-modern-world",  pyqs: ch5_pyqs, easyMCQ: ch5_easyMCQ, mediumMCQ: ch5_mediumMCQ, hardMCQ: ch5_hardMCQ },
    ];

    let totalResources = 0;
    for (const cd of chaptersData) {
      const chapter = map[cd.slug];
      if (!chapter) {
        console.warn(`⚠️  Chapter not found: ${cd.slug}`);
        continue;
      }
      await seedChapter(chapter, {
        pyqs:      cd.pyqs,
        easyMCQ:   cd.easyMCQ,
        mediumMCQ: cd.mediumMCQ,
        hardMCQ:   cd.hardMCQ,
      });
      totalResources += cd.pyqs.length + cd.easyMCQ.length + cd.mediumMCQ.length + cd.hardMCQ.length;
    }

    console.log("\n✅ History seed complete");
    console.log("─────────────────────────────────────────────────────");
    console.log(`Chapters seeded : ${chaptersData.length}`);
    console.log(`Total resources : ${totalResources}`);
    console.log(`Per chapter     : ${totalResources / chaptersData.length} (15 PYQs + 45 MCQs)`);
    console.log("─────────────────────────────────────────────────────");
    console.log("Run: node seeders/historySeed.js");

    process.exit(0);
  } catch (err) {
    console.error("❌ Seed failed:", err.message);
    process.exit(1);
  }
};

seedHistory();